// ══════════════════════════════════════════════════════════════════
//  🦀 Clawed 融合版 v5.6.0 · 全自动静默写回·零抖动兼容
//  · 日夜主题 · Clawed DJ 收藏 · 命中ID定点清洗 · 双模型质检返修
//  · 已移除预设条目扫描/分组开关 UI
//  · 词语型锁定全部标点；结构型允许必要标点调整，但锁死成对符号并审查标点质量
// ══════════════════════════════════════════════════════════════════

(function () {
  let ROOT = window;
  try { if(window.parent && window.parent !== window && window.parent.document) ROOT = window.parent; } catch(e) {}
  const DOC = ROOT.document;
  const CLAWED_VERSION = '5.6.1-no-jitter-visible-status-context-fix-st115';
  // Clawed 只清理自己的旧实例。对标 Orpheus 的逻辑，不再接管或销毁 Orpheus 运行实例。
  try { if (typeof ROOT.__CLAWED_CLEANUP__ === 'function') ROOT.__CLAWED_CLEANUP__('reload'); } catch(e) { console.warn('[Clawed] cleanup before reload failed:', e); }
  ['cc-btn','cc-overlay','cc-drawer','cc-bubble','cc-rescue-handle','cc-ext-menu-item','cc-sb','cc-style'].forEach(id => { try { DOC.getElementById(id)?.remove(); } catch(e) {} });
  ROOT.__CLAWED_INIT__ = true;
  ROOT.__CLAWED_VERSION__ = CLAWED_VERSION;
  const ccOwnerToken = 'clawed:' + Date.now() + ':' + Math.random().toString(36).slice(2);
  ROOT.__CLAWED_OWNER__ = ccOwnerToken;
  let ccCleaned = false;
  const ccTimers = new Set();
  const ccObservers = [];
  const ccCleanupListeners = [];
  const ccCleanupStops = [];
  function ccSetTimeout(fn, ms){
    if(ccCleaned) return null;
    let rec = null;
    const id = ROOT.setTimeout(()=>{
      if(rec) ccTimers.delete(rec);
      if(ccCleaned) return;
      try {
        const result = fn();
        if(result && typeof result.catch === 'function') result.catch(e=>console.warn('[Clawed timer async]', e));
      } catch(e) { console.warn('[Clawed timer]', e); }
    }, ms);
    rec = {type:'timeout', id};
    ccTimers.add(rec);
    return id;
  }
  function ccSetInterval(fn, ms){
    if(ccCleaned) return null;
    const id = ROOT.setInterval(()=>{
      if(ccCleaned) return;
      try {
        const result = fn();
        if(result && typeof result.catch === 'function') result.catch(e=>console.warn('[Clawed interval async]', e));
      } catch(e) { console.warn('[Clawed interval]', e); }
    }, ms);
    ccTimers.add({type:'interval', id});
    return id;
  }
  function addCleanupListener(target, type, fn, opts){
    try { target?.addEventListener?.(type, fn, opts); ccCleanupListeners.push({target,type,fn,opts}); } catch(e) {}
  }
  function addCleanupStop(stop){
    if(typeof stop === 'function') ccCleanupStops.push(stop);
    else if(typeof stop?.stop === 'function') ccCleanupStops.push(()=>stop.stop());
  }

  // ─── 工具 ─────────────────────────────────────────────────
  function isMobile() {
    return (DOC.documentElement.clientWidth||ROOT.innerWidth) < 768
      || /Mobi|Android|iPhone|iPad/i.test(navigator.userAgent);
  }
  function getFrameOffset() {
    try { if(!window.frameElement) return {left:0,top:0}; const r=window.frameElement.getBoundingClientRect(); return {left:r.left,top:r.top}; } catch(e) { return {left:0,top:0}; }
  }
  function positionBubble() {
    const vw=DOC.documentElement.clientWidth||ROOT.innerWidth, vh=DOC.documentElement.clientHeight||ROOT.innerHeight;
    const br=$btn.getBoundingClientRect(), bw=$bubble.offsetWidth||260, bh=$bubble.offsetHeight||60, GAP=12;
    const dw = drawerOpen ? (isMobile() ? ROOT.innerWidth*0.88 : 340) : 0;
    let left=br.left-bw-GAP; if(left<8) left=Math.min(br.right+GAP, vw-bw-dw-8);
    let top=br.top+br.height/2-bh/2; if(top<8)top=8; if(top+bh>vh-8)top=vh-bh-8;
    $bubble.style.setProperty('right','auto','important');
    $bubble.style.setProperty('bottom','auto','important');
    $bubble.style.setProperty('left',left+'px','important');
    $bubble.style.setProperty('top',top+'px','important');
  }
  const pick = arr => arr[Math.floor(Math.random()*arr.length)];
  function esc(s){ return String(s).replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c])); }

  // ─── 图标 ──────────────────────────────────────────────────
    function crabSvg(size) {
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="${size}" height="${size}" shape-rendering="crispEdges">
      <rect x="5" y="0" width="1" height="1" fill="#1A1A1A"/><rect x="6" y="0" width="1" height="1" fill="#1A1A1A"/>
      <rect x="9" y="0" width="1" height="1" fill="#1A1A1A"/><rect x="10" y="0" width="1" height="1" fill="#1A1A1A"/>
      <rect x="4" y="1" width="4" height="1" fill="#1A1A1A"/><rect x="8" y="1" width="4" height="1" fill="#1A1A1A"/>
      <rect x="5.5" y="1" width="0.8" height="0.8" fill="#FFFFFF"/><rect x="9.7" y="1" width="0.8" height="0.8" fill="#FFFFFF"/>
      <rect x="3" y="2" width="10" height="4" fill="#1A1A1A"/>
      <rect x="4.5" y="3" width="1.5" height="1.5" fill="#FFFFFF"/><rect x="10" y="3" width="1.5" height="1.5" fill="#FFFFFF"/>
      <rect x="5.2" y="3.8" width="0.7" height="0.7" fill="#1A1A1A"/><rect x="10.7" y="3.8" width="0.7" height="0.7" fill="#1A1A1A"/>
      <rect x="0" y="3" width="1" height="1" fill="#1A1A1A"/><rect x="0" y="4" width="2" height="1" fill="#1A1A1A"/>
      <rect x="1" y="5" width="1" height="1" fill="#1A1A1A"/><rect x="1" y="6" width="2" height="1" fill="#1A1A1A"/>

      <rect x="3" y="6" width="10" height="5" fill="#E88C7E"/><rect x="3" y="6" width="10" height="0.4" fill="#F5A99B"/>
      <rect x="0" y="7" width="3" height="3" fill="#E88C7E"/><rect x="13" y="7" width="3" height="3" fill="#E88C7E"/>
      <rect x="5" y="7.4" width="1.5" height="1.5" fill="#1A1A1A"/><rect x="9.5" y="7.4" width="1.5" height="1.5" fill="#1A1A1A"/>
      <rect x="3" y="11" width="1.7" height="3" fill="#E88C7E"/><rect x="5.5" y="11" width="1.7" height="3" fill="#E88C7E"/>
      <rect x="8.8" y="11" width="1.7" height="3" fill="#E88C7E"/><rect x="11.3" y="11" width="1.7" height="3" fill="#E88C7E"/>
    </svg>`;
  }

  function crabDJ(size) {
    const PAL={o:'#E0795E',t:'#ECA088',s:'#C25A3E',d:'#A8482F',k:'#1A1A1A',B:'#33373B',p:'#26292C',h:'#565D63'};
    const W=16,H=16;
    const G=Array.from({length:H},()=>new Array(W).fill(null));
    const ly=12;
    [[3,ly],[6,ly],[9,ly],[12,ly]].forEach(([x,y])=>{for(let j=0;j<3;j++)G[y+j][x]='o';G[y+2][x]='d';});
    for(let j=0;j<9;j++) for(let i=0;i<12;i++) G[2+j][2+i]='o';
    for(let i=0;i<10;i++) G[1][3+i]='t';
    for(let i=0;i<12;i++) G[10][2+i]='s';
    [[4,4],[4,5],[5,4],[5,5]].forEach(([x,y])=>G[y][x]='k');
    [[10,4],[10,5],[11,4],[11,5]].forEach(([x,y])=>G[y][x]='k');
    for(let i=4;i<12;i++) G[0][i]='B';
    G[1][3]='B';G[1][12]='B';G[2][2]='B';G[2][13]='B';
    for(let j=0;j<4;j++) for(let i=0;i<3;i++) G[6+j][i]='p';
    for(let j=0;j<4;j++) G[6+j][0]='h';
    for(let j=0;j<4;j++) for(let i=0;i<3;i++) G[6+j][13+i]='p';
    for(let j=0;j<4;j++) G[6+j][15]='h';
    let rects='';
    for(let y=0;y<H;y++) for(let x=0;x<W;x++){const c=G[y][x];if(!c)continue;rects+=`<rect x="${x}" y="${y}" width="1" height="1" fill="${PAL[c]}"/>`;}
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${W} ${H}" width="${size}" height="${size}" shape-rendering="crispEdges">${rects}</svg>`;
  }


  function oImg(size) { return crabSvg(size); }

  // ─── 配置 ──────────────────────────────────────────────────
  const STORE_KEY = 'crab_companion_v3';
  const DEFAULTS = {
    apiKey:'', city:'Petaling Jaya', interval:30, rest:true, weather:true,
    openaiKey:'', aiBaseUrl:'https://api.openai.com/v1', aiModel:'', aiInterval:5, aiEnabled:true,
    idle:true, idleMins:8, timeGreet:true, strategyEnabled:true, nickname:'',
    personality:'tsundere', customPersonality:'',
    purifyEnabled:false, purifyAiEnabled:true,
    autoFixEnabled:true, autoFixMaxRounds:1,
    purifyQaEnabled:false, purifyQaScope:'high', purifyQaUseMainApi:true,
    purifyQaKey:'', purifyQaBaseUrl:'https://api.openai.com/v1', purifyQaModel:'', purifyQaRepairRounds:1,
    floatEnabled:true, extensionMenuEnabled:true,
    theme:'day',
  };
  let cfg = {...DEFAULTS};
  try { Object.assign(cfg, JSON.parse(ROOT.localStorage.getItem(STORE_KEY)||'{}')); } catch(e) {}
  // 兼容旧配置：旧版没有轮次与质检字段时使用保守默认值。
  cfg.autoFixMaxRounds = Math.max(1, Math.min(6, parseInt(cfg.autoFixMaxRounds,10) || 1));
  cfg.purifyQaScope = cfg.purifyQaScope === 'all' ? 'all' : 'high';
  cfg.purifyQaRepairRounds = Math.max(1, Math.min(2, parseInt(cfg.purifyQaRepairRounds,10) || 1));
  function saveCfg() { ROOT.localStorage.setItem(STORE_KEY, JSON.stringify(cfg)); }
  const startTime = Date.now();

  // ─── 禁词表 ────────────────────────────────────────────────
  const FORB_WORDS = [
    '无力感','面无表情','剧烈','极度','深深','震惊','紧绷','收紧',
    '死死攥住','仿佛','好像在','指节','指尖泛白','指尖发白','身体诚实','胸腔震动',
    '涟漪','石子','心湖','小兽','野兽','光圈','光斑','深潭',
    '深海','刀刃','烙印','炸开','炸裂','一丝','一缕','一抹',
    '猛地','瞬间','刹那','狡黠','玩味','都在诉说','不容置疑','无法抗拒',
    '前所未有','无法形容','格格不入','审视','荷尔蒙','邪肆','邪魅','砂纸',
    '羽毛','吞没','熠熠','矜持','精准','精确','灼热','滚烫',
    '沸腾','炙热','攥紧拳头','握紧','僵硬','一片空白','电流','闪电',
    '如释重负','咬紧','咬牙','木偶','某种','沙哑','突然','不由得',
    '不禁','忍不住','一时间','突然觉得','莫名感到','似乎','一股暖流','心头一紧',
    '失落感','挫败感','孤独感','氛围','难以言喻','不可名状','深吸一口气','轻叹一声',
    '舔了舔嘴唇','两秒','三秒','五秒','厘米','毫米','心海','水面',
    '湖面','死水','井','石头','巨石','碎石','投入','抛入',
    '丢入','坠入','扔进','沉入','语气','语调','陈述','问句',
    '问号','嘶哑','嗡嗡','仿佛在说','正在','针','钉子','烙铁',
    '入骨','爆发','炸弹','地雷','原子弹','核弹','子弹','轰地一下',
    '轰然','烧红','光点','光带','闪烁','巨兽','小妖精','妖精',
    '人偶','展品','雕塑','机械','机器人','冰冷','手术刀','解剖',
    '外科手术','精密仪器','仪器','精密计算','训练有素的本能','狂热','信徒','仪式',
    '祭品','献祭','打转','转圈','画圈','麻木','绝望','激烈',
    '恐慌','激动','愤怒','僵住','面色尽失','血压','锁骨','喉结',
    '指节分明','指节发白','齿间','痞气','腻','玩火','娘里娘气','自暴自弃',
    '残忍','狠厉','该死','弧度','在这个空间里','形成鲜明对比','无可指摘','不可抗拒',
    '汇入车流','取而代之','并没有立刻','审判'
  ];
  const FORB_ANATOMY = [
    '粘膜','筋膜','韧带','肌腱','软骨','括约肌','胰腺','胆囊',
    '卵巢','前列腺','血管','动脉','静脉','神经','淋巴','虹膜',
    '锁骨','肋骨','五指','肩胛','骨节','背脊','脊背','颧骨',
    '胯骨','腰椎','颈椎','胸椎','尾椎','髋骨','耻骨','骨缝',
    '脉搏','喉结','鼓膜','肩胛骨','胸骨','头骨','颅骨','额骨',
    '眉骨','鼻骨','鼻梁骨','颌骨','下颌骨','上颌骨','颚骨','腭骨',
    '颞骨','枕骨','顶骨','蝶骨','筛骨','泪骨','犁骨','舌骨',
    '牙槽骨','椎骨','脊柱','脊椎','骶骨','骶椎','尾骨','肋下',
    '颧弓','骨盆','肱骨','尺骨','桡骨','腕骨','掌骨','指骨',
    '髂骨','坐骨','股骨','髌骨','胫骨','腓骨','跗骨','距骨',
    '跟骨','跖骨','趾骨','头盖骨','下巴骨','肩骨','背骨','脊梁骨',
    '手骨','脚骨','臂骨','腿骨','肘骨','踝骨','膝盖骨','盆骨',
    '荐骨'
  ];
  const FORB_PATS = [
    {re:/(^|[^是])(?:已经|已|早就|并|也|倒也|但)?不是[^。！？\n]{1,50}?(?:了)?(?:[，,、；;]\s*|[。！？!?]\s*)?(?:是|而是|其实是|倒是|却是|只是|反而是|就是|就像是|更像|更接近|倒像|倒不如说)/,label:'否定-转折'},
    {re:/(?:不再是|再不是)[^。！？\n]{1,50}?(?:[，,、；;]\s*)?(?:是|而是|更像|更接近|倒像|倒不如说)/,label:'否定-转折'},
    {re:/并非[^。！？\n]{1,50}?(?:而是|只是|不过是|更像|更接近|倒像)/,label:'否定-转折'},
    {re:/不像[^。！？\n]{1,40}?(?:像|更像|倒像)/,label:'不像A像B'},
    {re:/与其说[^。！？\n]{1,50}?不如说/,label:'与其说…不如说'},
    {re:/(?:算不上|说不上|称不上|不完全是|不至于|不算|谈不上|够不上)[^。！？\n]{0,50}?(?:[，,、；;]\s*)?(?:只是|更像|倒像|不过是|更接近|倒不如说|是)/,label:'否定校准'},
    {re:/(?:不是|也不是|倒也不是|并非|不像|不算|算不上|说不上|称不上|不完全是|不至于|谈不上|够不上|没有)[^。！？\n]{0,50}?(?:只是|更像|倒像|不过是|更接近|倒不如说)/,label:'重框架连接'},
    {re:/(?:既没有|没有)[^。！？\n]{1,30}?也没有[^。！？\n]{1,30}/,label:'缺席校准'},
    {re:/也不是|倒也不是|说不上是/,label:'否定软化'},
    {re:/那是[^，。！？\n]{1,20}的感觉/,label:'那是…的感觉'},
    {re:/那种[^的，。！？\n]{1,15}的感觉/,label:'那种X的感觉'},
    {re:/(?:更关键的是|我知道|我看见)(?:[^，。])/,label:'叙述者介入'},
    {re:/(?:终于|总算|到底)(?:等到|才|让|来|走|完)/,label:'解脱标记'},
    {re:/(?:\d+|[一二两三四五六七八九十半]+)(?:秒|次|下(?!午|班|课)|拍|步|厘米|毫米|个字)/,label:'数字精确量'},
    {re:/[二三四五六七八九十]分[^，。！？\n]{0,8}意/,label:'X分Y意'},
    {re:/语气(?:平淡|柔软|低沉|冷淡).{0,6}(?:像|就像)/,label:'语气比喻'},
    {re:/(?:像|跟|和|如同|仿佛)(?:是)?(?:在)?(?:聊|讨论|谈论|谈|说|汇报|播报|念经|背书|做报告)(?:起)?[^。！？\n]{0,12}(?:天气|一样|似的|那样|般)/,label:'比喻性情态状语'},
    {re:/用(?:聊|讨论|谈|说|汇报|播报)[^。！？\n]{0,10}的(?:口气|口吻|语气|腔调|态度)/,label:'比喻性情态状语'},
    {re:/(?:冷冷|淡淡|愤怒地|微笑|温柔|平静|低沉|沙哑|冰冷|轻声|厉声)(?:地)?(?:道|说|开口|问|吼|喊|笑道)/,label:'情绪标签式对话'},
    {re:/(?:他|她|你|我)?是那种[^。！？\n]{1,40}的人/,label:'翻译腔人设句'},
    {re:/呈现出[^。！？\n]{1,40}的状态/,label:'翻译腔状态句'},
    {re:/(?:深吸一口气|轻叹一声|舔了舔嘴唇)/,label:'无功能呼吸叹气'},
    {re:/以一种[^。！？\n]{1,40}(?:方式|姿态|状态)/,label:'叙述重量-方式腔'},
    {re:/近乎[^。！？\n]{1,30}的方式/,label:'叙述重量-方式腔'},
    {re:/用的那种[^。！？\n]{1,50}/,label:'动作后注释'},
    {re:/(?:呈现|表现|显露|暴露)出[^。！？\n]{1,40}(?:状态|姿态|态势)/,label:'翻译腔状态句'},
  ];

  function scanForbidden(text) {
    const found=[];
    getPurifyWordMatches(text).sort((a,b)=>b.word.length-a.word.length).forEach(item=>{
      if(item.word && !found.includes(item.word)) found.push(item.word);
    });
    getAllPatternRules().forEach(p=>{
      const tag='【'+p.label+'】';
      // 不能只用 re.test(text)：像 <novel_header> / [第 8 章] 这类结构头会误触发“数字精确量”，
      // 但它不应该进入净化。这里先确认存在可改写的正文命中单元。
      if(patternHasUsableHit(text, p) && !found.includes(tag)) found.push(tag);
    });
    return normalizeActiveFound(found);
  }


  // ─── 旧版直替映射已停用 ───────────────────────────────
  // v5.1 起不再本地机械替换；词条和句式只作为“告诉 AI 怎么改”的规则。
  const DEFAULT_PURIFY_MAP = {};

  // ─── 净化规则：词条和句式分开管理（指令式，不做机械直替） ──────
  const CUSTOM_WORDS_KEY = 'clawed_custom_words_v1';
  const CUSTOM_PATTERNS_KEY = 'clawed_custom_patterns_v1';
  const BUILTIN_WORD_RULES_KEY = 'clawed_builtin_word_rules_v1';
  const BUILTIN_PATTERN_RULES_KEY = 'clawed_builtin_pattern_rules_v1';
  const DISABLED_BUILTINS_KEY = 'clawed_disabled_builtins_v1';
  const PURIFY_SYSTEM_PROMPT_KEY = 'clawed_purify_system_prompt_v1';
  const CATEGORY_RULES_KEY = 'clawed_category_rules_v1';
  const CLAWED_PURIFY_MIGRATION_KEY = 'clawed_purify_namespace_migrated_v1';
  const LEGACY_ORPHEUS_KEYS = {
    [CUSTOM_WORDS_KEY]:'orpheus_custom_words',
    [CUSTOM_PATTERNS_KEY]:'orpheus_custom_patterns',
    [BUILTIN_WORD_RULES_KEY]:'orpheus_builtin_word_rules_v52',
    [BUILTIN_PATTERN_RULES_KEY]:'orpheus_builtin_pattern_rules_v52',
    [DISABLED_BUILTINS_KEY]:'orpheus_disabled_builtins_v52',
    [PURIFY_SYSTEM_PROMPT_KEY]:'orpheus_purify_system_prompt_v544_scope_style',
    [CATEGORY_RULES_KEY]:'orpheus_category_rules_v53'
  };
  function migrateLegacyPurifyStorageOnce(){
    try{
      if(ROOT.localStorage.getItem(CLAWED_PURIFY_MIGRATION_KEY)) return;
      Object.entries(LEGACY_ORPHEUS_KEYS).forEach(([nextKey, oldKey]) => {
        if(ROOT.localStorage.getItem(nextKey) != null) return;
        const legacy = ROOT.localStorage.getItem(oldKey);
        if(legacy != null) ROOT.localStorage.setItem(nextKey, legacy);
      });
      ROOT.localStorage.setItem(CLAWED_PURIFY_MIGRATION_KEY, String(Date.now()));
