  const PURIFY_IGNORED_LINE_RE = /^\s*(?:\[\s*(?:TITLE|EPIGRAPH|TIME|CAST|LOCATION|STYLE|SUMMARY|AUTHOR|NOTE|CHAPTER|SCENE|POV|WEATHER|BGM|TAGS?)\s*\][^\n]*|\[?\s*第\s*(?:\d+|[一二两三四五六七八九十百千万零〇]+)\s*(?:章|节|幕|卷|回)\s*\]?)\s*$/gmi;

  function maskPurifyIgnoredBlocks(text) {
    const preserve = m => String(m || '').replace(/[^\n]/g, ' ');
    return String(text || '')
      .replace(PURIFY_IGNORED_BLOCK_RE, preserve)
      .replace(PURIFY_IGNORED_LINE_RE, preserve);
  }

  function stripPurifyIgnoredBlocks(text) {
    return String(text || '')
      .replace(PURIFY_IGNORED_BLOCK_RE, '\n')
      .replace(PURIFY_IGNORED_LINE_RE, '\n')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  }

  function getPurifyDocumentFromRaw(raw){
    const blocks=collectContextBlocks(raw);
    const segments=[];
    let globalStart=0;
    blocks.forEach((block,contextIndex)=>{
      const body=String(block.body || '');
      const scanText=maskPurifyIgnoredBlocks(body);
      segments.push({contextIndex,body,scanText,globalStart,globalEnd:globalStart+scanText.length,rawBodyStart:block.bodyStart,rawBodyEnd:block.bodyEnd,wrapperKind:block.kind});
      globalStart += scanText.length + 2;
    });
    const scanText=segments.map(x=>x.scanText).join('\n\n');
    const displayText=segments.map(x=>stripPurifyIgnoredBlocks(x.body)).filter(Boolean).join('\n\n');
    return {scanText, displayText, segments, blocks};
  }

  function getPurifyTextFromRaw(raw) {
    return getPurifyDocumentFromRaw(raw).scanText;
  }

  function locatePurifyContext(doc, globalStart, globalEnd){
    const d=doc || {segments:[]};
    for(const seg of d.segments || []){
      if(globalStart >= seg.globalStart && globalEnd <= seg.globalEnd){
        return {contextIndex:seg.contextIndex, start:globalStart-seg.globalStart, end:globalEnd-seg.globalStart};
      }
    }
    return null;
  }

  function looseKeyRegex(key){
    const k = String(key || '').trim();
    if(!k) return null;
    try {
      // 空白/换行差异是二轮写回失败的常见原因：AI 按 key 返回了建议，但正文被 ST 重渲染后空格变化。
      const src = k.replace(/[.*+?^${}()|[\]\\]/g,'\\$&').replace(/\s+/g, '\\s*');
      return new RegExp(src);
    } catch(e) { return null; }
  }

  function applyMapToTextLoose(text, map){ return actionPreviewText(text,map); }
  function guardedApplyMapLoose(text, map){ return actionPreviewText(text,map); }

  function validateActionAtApply(body, action){
    const current=String(body || '').slice(action.start,action.end);
    if(current!==action.from) return {ok:false,reason:'stale'};
    const candidate=String(body || '').slice(0,action.start)+action.to+String(body || '').slice(action.end);
    if(protectedSymbolSeqChanged(current,action.to) || (!quotePairingBroken(body) && quotePairingBroken(candidate))) return {ok:false,reason:'symbols'};
    if(introducedDuplication(body,candidate)) return {ok:false,reason:'duplication'};
    return {ok:true};
  }

  function applyMapToContext(raw, map) {
    const source=String(raw || '');
    const blocks=collectContextBlocks(source);
    const actions=Object.values(normalizePurifyMap(map));
    const byContext=new Map();
    actions.forEach(a=>{if(!byContext.has(a.contextIndex))byContext.set(a.contextIndex,[]);byContext.get(a.contextIndex).push(a)});
    const applied=[], rejected=[];
    let replaced=source;
    // 从后往前写，避免前一个 context 长度变化影响后一个 context 的原始坐标。
    for(let contextIndex=blocks.length-1;contextIndex>=0;contextIndex--){
      const block=blocks[contextIndex];
      let next=String(block.body || '');
      const list=(byContext.get(contextIndex)||[]).sort((a,b)=>b.start-a.start);
      for(const action of list){
        const gate=validateActionAtApply(next,action);
        if(!gate.ok){rejected.push({...action,reason:gate.reason});continue;}
        next=next.slice(0,action.start)+action.to+next.slice(action.end);
        applied.push(action);
      }
      if(next!==block.body) replaced=replaced.slice(0,block.bodyStart)+next+replaced.slice(block.bodyEnd);
    }
    symbolGuardBlocked += rejected.filter(x=>x.reason==='symbols'||x.reason==='duplication').length;
    return {text:replaced,scoped:applied.length>0,applied,rejected};
  }

  function getMesIndexFromEl(mesEl) {
    const mid = mesEl?.getAttribute?.('mesid') ?? mesEl?.dataset?.mesid;
    const idx = parseInt(mid, 10);
    return Number.isInteger(idx) ? idx : -1;
  }

  function getMesElByIndex(idx) {
    const chatDom = DOC.querySelector('#chat');
    if (!chatDom || idx < 0) return null;
    return chatDom.querySelector('.mes[mesid="' + idx + '"], .mes[data-mesid="' + idx + '"]');
  }

  function getTargetMessageFromEl(mesEl) {
    const ctx = ROOT.SillyTavern?.getContext();
    const chat = ctx?.chat;
    if (!Array.isArray(chat)) return null;
    const idx = getMesIndexFromEl(mesEl);
    if (idx >= 0 && chat[idx]) return { ctx, chat, idx, raw: chat[idx].mes || '', mesEl };
    return null;
  }

  function getTargetMessageByIndex(idx) {
    const ctx = ROOT.SillyTavern?.getContext();
    const chat = ctx?.chat;
    if (!Array.isArray(chat) || idx < 0 || !chat[idx]) return null;
    return { ctx, chat, idx, raw: chat[idx].mes || '', mesEl: getMesElByIndex(idx) };
  }

  function getLatestAiTarget() {
    const ctx = ROOT.SillyTavern?.getContext();
    const chat = ctx?.chat;
    if (!Array.isArray(chat) || !chat.length) return null;
    const candidates=[];
    const seen=new Set();
    const add=(target)=>{
      const idx=target?.idx;
      const msg=Number.isInteger(idx)?target?.chat?.[idx]:null;
      if(!msg || seen.has(idx) || msg.is_user || msg.is_system || !String(msg.mes || '').trim()) return;
      seen.add(idx);
      candidates.push({...target,raw:msg.mes || ''});
    };

    // 先按 DOM 的真实倒序收集，再补 chat 数组中未渲染/被折叠的消息。
    [...DOC.querySelectorAll('#chat .mes')].reverse().forEach(mesEl=>{
      if(mesEl.getAttribute('is_user')==='true' || mesEl.dataset?.isUser==='true') return;
      add(getTargetMessageFromEl(mesEl));
    });
    for(let idx=chat.length-1;idx>=0;idx--) add({ctx,chat,idx,raw:chat[idx]?.mes || '',mesEl:getMesElByIndex(idx)});

    // 关键修复：优先返回最近一条“确实存在可扫描 context 正文”的 AI 消息，
    // 不再被后置的插件提示、空壳角色消息或状态消息抢走扫描目标。
    for(const target of candidates){
      const doc=getPurifyDocumentFromRaw(target.raw);
      if(doc.segments.length && doc.scanText.trim()) return target;
    }
    return candidates[0] || null;
  }

  function cloneRegexGlobal(re) {
    return new RegExp(re.source, re.flags.includes('g') ? re.flags : re.flags + 'g');
  }

  // 对话/心声标记：净化单元绝不跨越或包含这些符号，保证 AI 永远碰不到引号星号。
  const QUOTE_OPEN = '\u201c\u2018\u0022\u0027\u300c\u300e\u300a\uff08([`*';
  const QUOTE_CLOSE = '\u201d\u2019\u0022\u0027\u300d\u300f\u300b\uff09)]`*';
  function trimUnitBounds(text, start, end){
    const s=String(text || '');
    let l=Math.max(0,start), r=Math.min(s.length,end);
    while(l<r && /\s/.test(s[l])) l++;
    while(r>l && /\s/.test(s[r-1])) r--;
    return {start:l,end:r,text:s.slice(l,r)};
  }
  function expandToSentenceBounds(text, start, end) {
    const s=String(text || '');
    const leftMarks = '\n。！？!?' + QUOTE_OPEN + QUOTE_CLOSE;
    const stopMarks = '。！？!?';
    const rightStops = stopMarks + QUOTE_OPEN + QUOTE_CLOSE + '\n';
    let l = start;
    while (l > 0 && !leftMarks.includes(s[l - 1])) l--;
    let r = end;
    while (r < s.length && !rightStops.includes(s[r])) r++;
    if (r < s.length && stopMarks.includes(s[r])) r++;
    return trimUnitBounds(s,l,r);
  }
  function expandToSentence(text, start, end) { return expandToSentenceBounds(text,start,end).text; }

  function expandToClauseBounds(text, start, end) {
    const s = String(text || '');
    const leftMarks = '\n。！？!?，,；;：:' + QUOTE_OPEN + QUOTE_CLOSE;
    const punctMarks = '。！？!?，,；;：:';
    const rightStops = punctMarks + QUOTE_OPEN + QUOTE_CLOSE + '\n';
    let l = Math.max(0, start);
    while (l > 0 && !leftMarks.includes(s[l - 1])) l--;
    let r = Math.min(s.length, end);
    while (r < s.length && !rightStops.includes(s[r])) r++;
    if (r < s.length && punctMarks.includes(s[r])) r++;
    let unit = trimUnitBounds(s,l,r);
    const bare = unit.text.replace(/[\s，,；;：:。！？!?]+/g, '');
    if (bare.length < 4) return expandToSentenceBounds(s, start, end);
    return unit;
  }
  function expandToClause(text, start, end) { return expandToClauseBounds(text,start,end).text; }

  function expandToPurifyUnitBounds(text, start, end, mode) {
    return mode === 'sentence' ? expandToSentenceBounds(text, start, end) : expandToClauseBounds(text, start, end);
  }
  function expandToPurifyUnit(text, start, end, mode) {
    return expandToPurifyUnitBounds(text,start,end,mode).text;
  }

  const CLAUSE_LEVEL_PATTERN_LABELS = new Set([
    '数字精确量','叙述重量-方式腔','动作后注释','解脱标记','情绪标签式对话','无功能呼吸叹气','比喻性情态状语'
  ]);

  function isStructuralPurifyUnit(unit, label){
    const s = String(unit || '').trim();
    const lab = String(label || '');
    if(!s) return true;
    // 小说头、章节号、TITLE/EPIGRAPH 等元信息不要当正文清洗；
    // 截图里的 [第 8 章] 命中“数字精确量”就是这个误触发。
    if(/<\/?(?:novel_header|context|thinking|metadata|meta)[^>]*>/i.test(s)) return true;
    if(/^\[(?:TITLE|EPIGRAPH|SUMMARY|AUTHOR|NOTE)\]/i.test(s)) return true;
    if(lab === '数字精确量' && /^\[?第\s*(?:\d+|[一二两三四五六七八九十百千万零〇]+)\s*(?:章|节|幕|卷|回)\]?$/i.test(s)) return true;
    return false;
  }

  function collectPatternUnitsForRule(text, p) {
    const out = [];
    if(!p) return out;
    const re = cloneRegexGlobal(p.re);
    const mode = CLAUSE_LEVEL_PATTERN_LABELS.has(p.label) ? 'clause' : 'sentence';
    let m;
    while ((m = re.exec(text))) {
      let start = m.index;
      let end = m.index + m[0].length;
      const leadingStop = String(m[0] || '').match(/^[。！？!?\n]/);
      if (leadingStop) start += leadingStop[0].length;
      const unit = expandToPurifyUnitBounds(text, start, end, mode);
      if (unit.text && !isStructuralPurifyUnit(unit.text, p.label)) out.push({...unit, matchStart:start, matchEnd:end});
      if (m[0].length === 0) re.lastIndex++;
    }
    return out;
  }
  function collectPatternSentencesForRule(text, p) {
    return [...new Set(collectPatternUnitsForRule(text,p).map(x=>x.text))];
  }

  function patternHasUsableHit(text, p){
    return collectPatternSentencesForRule(text, p).length > 0;
  }

  function collectPatternSentences(text, labels) {
    const out = [];
    getAllPatternRules().filter(p => labels.includes(p.label)).forEach(p => {
      collectPatternSentencesForRule(text, p).forEach(sent => { if(sent && !out.includes(sent)) out.push(sent); });
    });
    return out;
  }


  // 扫描本轮 <context> 内容

  function clearPurifyState(force){
    if(!force && purifyBusy) return; // 净化进行中，不清状态
    lastPurify=null; lastPurifyMap=null; purifyCleanText=''; purifyRoundInfo=null; lastApplyGuardFailure=null;
    updatePurifyArea();
  }

  function hasPendingPurifyResult(){
    // AI 已产出但用户还没点“应用到正文”时，不允许后台自动扫描覆盖状态。
    // 修复：切到正文/其他 Tab 再回来后，“待应用”按钮消失的问题。
    return !!(lastPurify && lastPurifyMap && purifyCleanText);
  }

  function markPurifyRulesChanged(){
    // 词库/句式变化后，旧的检测结果已经不可信；清空并允许重新扫描。
    try { clearPurifyState(true); } catch(e) {}
    try { autoScanGuard=''; } catch(e) {}
    try { ccSetTimeout(()=>{ if(!purifyBusy) scanContextMsg({silent:true, force:true}); }, 80); } catch(e) {}
  }

  function scanContextMsg(opts={}) {
    const silent = !!opts.silent;
    const force = !!opts.force;
    if (purifyBusy) {
      if(!silent) showBubble('⏳ 自动清洗正在进行中' + (purifyRoundInfo?.round ? '（第'+purifyRoundInfo.round+'轮）' : '') + '，当前按钮没有失效；完成后会自动刷新结果。',7000);
      return false;
    }
    if (!force && hasPendingPurifyResult()) {
      updatePurifyArea();
      if(!silent) showBubble('已有 AI 净化结果待应用；请先点“应用到正文”或“清除”，避免被重新扫描覆盖。', 7000);
      return true;
    }
    try {
      const target = getLatestAiTarget();
      if (!target) { clearPurifyState(); if(!silent) showBubble('⚠️ 读取不到聊天记录'); return false; }
      const doc = getPurifyDocumentFromRaw(target.raw);
      const text = doc.scanText;
      if (!text.trim()) { clearPurifyState(); if(!silent) showBubble('⚠️ 最近的 AI 正文中没有解析到可扫描的 <context>。已兼容标签空格、属性和 &lt;context&gt; 转义；当前候选楼层：'+target.idx,9000); return false; }
      const found = scanForbidden(text);
      if (!found.length) { clearPurifyState(); if(!silent) showBubble('✓ 最新 AI 回复 context 未检测到八股词'); return false; }
      const stats=getPurifyStats(text,found,doc);
      lastPurify = { text, displayText:doc.displayText, doc, found, hitItems:stats.hits, stats, mesEl: target.mesEl, idx: target.idx };
      lastPurifyMap = null; purifyRoundInfo = null; purifyCleanText = ''; lastApplyGuardFailure=null;
      const autoQueued = cfg.autoFixEnabled ? queueAutoPurifyForTarget(target, 'scan') : false;
      if(!autoQueued) updatePurifyArea();
      if(!silent && !autoQueued){
        showBubble('⚡ 最新 AI 回复 context 命中 ' + stats.occurrenceCount + ' 处（' + stats.ruleCount + ' 类规则）：' + found.slice(0, 4).join(' · ') + (found.length > 4 ? ' 等' + found.length + '类' : ''), 8000);
        if (activeTab !== 'purify') switchTab('purify');
      }
      return true;
    } catch(e) { clearPurifyState(); if(!silent) showBubble('扫描出错: ' + e.message); return false; }
  }

  let autoPurifyKickGuard = '';
  function queueAutoPurifyForTarget(target, source){
    if(!cfg.autoFixEnabled || purifyBusy || hasPendingPurifyResult()) return false;
    const idx = Number.isInteger(target?.idx) ? target.idx : -1;
    if(idx < 0) return false;
    const raw = String(target?.raw || target?.chat?.[idx]?.mes || '');
    // 已经由本插件写回、且正文没有再次变化的楼层，不因打开面板/聚焦输入框而突破玩家设置的轮数上限。
    if(isAutoPurifySelfWrite(idx, raw)) return false;
    const key = idx + ':' + purifyGuardHash(raw);
    if(autoPurifyKickGuard === key) return false;
    autoPurifyKickGuard = key;
    const mesEl = target?.mesEl || getMesElByIndex(idx);
    ccSetTimeout(async()=>{
      try{
        if(!cfg.autoFixEnabled || purifyBusy || hasPendingPurifyResult()) return;
        const freshTarget = getTargetMessageByIndex(idx) || (mesEl ? getTargetMessageFromEl(mesEl) : null);
        if(!freshTarget || purifyGuardHash(freshTarget.raw) !== purifyGuardHash(raw)) return;
        if(isAutoPurifySelfWrite(idx, freshTarget.raw)) return;
        if(!lastPurify || lastPurify.idx !== idx){
          const fresh = rescanPurifyTarget(idx, mesEl);
          if(!fresh.ok || fresh.clean) return;
        }
        await autoRunPurify(1, idx, mesEl || freshTarget.mesEl);
      } finally {
        if(autoPurifyKickGuard === key) autoPurifyKickGuard = '';
      }
    }, source === 'event' ? 120 : 60);
    return true;
  }

  function autoScanLatestContext(){
    if(purifyBusy || hasPendingPurifyResult()) return; // 净化进行中 / 有待应用结果，不打断不覆盖
    scanContextMsg({silent:true});
    ccSetTimeout(()=>{ if(!purifyBusy && !hasPendingPurifyResult()) scanContextMsg({silent:true}); }, 250);
  }

  function hlForbidden(text, found) {
    let h=esc(text);
    found.filter(f=>!f.startsWith('【')).sort((a,b)=>b.length-a.length).forEach(w=>{
      const e=esc(w).replace(/[.*+?^${}()|[\]\\]/g,'\\$&');
      h=h.replace(new RegExp(e,'g'),`<mark style="background:rgba(192,57,43,.15);color:#c0392b;border-radius:2px;padding:0 1px;">${esc(w)}</mark>`);
    });
    return h.replace(/\n/g,'<br>');
  }

  // ─── 应用替换：DOM TreeWalker 只动文本节点，保留所有格式 ──────


  function getLiveMessageElement(idx, fallback){
    return getMesElByIndex(idx) || (fallback?.isConnected ? fallback : null);
  }

  function captureChatViewport(mesEl){
    const chatEl=DOC.querySelector('#chat');
    const liveMes=mesEl?.isConnected ? mesEl : null;
    const rect=liveMes?.getBoundingClientRect?.();
    return {
      chatEl,
      scrollTop:chatEl?.scrollTop || 0,
      atBottom:!!chatEl && (chatEl.scrollHeight-chatEl.scrollTop-chatEl.clientHeight<6),
      mesTop:rect?.top,
      oldScrollBehavior:chatEl?.style?.scrollBehavior || '',
      oldOverflowAnchor:chatEl?.style?.overflowAnchor || ''
    };
  }

  function stabilizeChatViewport(state, mesEl){
    const chatEl=state?.chatEl;
    if(!chatEl) return;
    try{
      chatEl.style.scrollBehavior='auto';
      chatEl.style.overflowAnchor='none';
      const restore=()=>{
        if(state.atBottom) chatEl.scrollTop=Math.max(0,chatEl.scrollHeight-chatEl.clientHeight);
        else if(Number.isFinite(state.mesTop) && mesEl?.isConnected){
          const nowTop=mesEl.getBoundingClientRect().top;
          chatEl.scrollTop += nowTop-state.mesTop;
        } else chatEl.scrollTop=state.scrollTop;
      };
      restore();
      const raf=ROOT.requestAnimationFrame?.bind(ROOT) || (fn=>ccSetTimeout(fn,16));
      raf(()=>{ restore(); raf(()=>{
        restore();
        chatEl.style.scrollBehavior=state.oldScrollBehavior;
        chatEl.style.overflowAnchor=state.oldOverflowAnchor;
      }); });
    }catch(e){}
  }

  function collectTextNodes(root){
    const out=[];
    if(!root) return out;
    const walker=DOC.createTreeWalker(root,4);
    let node;
    while((node=walker.nextNode())) out.push(node);
    return out;
  }

  function planSilentTextPatch(textEl, actions, rawBefore){
    const nodes=collectTextNodes(textEl);
    let flat='';
    const spans=nodes.map(node=>{
      const start=flat.length;
      flat+=node.nodeValue || '';
      return {node,start,end:flat.length};
    });
    const ordered=[...(actions || [])].sort((a,b)=>(a.contextIndex-b.contextIndex)||(a.start-b.start));
    const contextRanges=findContextRangesInVisibleText(flat,rawBefore || '');
    const plans=[];
    let cursor=0;
    for(const action of ordered){
      const from=String(action?.from || '');
      if(!from) return null;
      const scope=contextRanges[action.contextIndex] || {start:0,end:flat.length};
      let idx=flat.indexOf(from,Math.max(cursor,scope.start));
      if(idx<0 || idx+from.length>scope.end) idx=flat.indexOf(from,scope.start);
      if(idx<0 || idx+from.length>scope.end) return null;
      const end=idx+from.length;
      const span=spans.find(x=>idx>=x.start && end<=x.end);
      // 只在同一个文本节点内定点替换；跨标签/跨节点交给遮罩重渲染兜底，避免破坏 Markdown 结构。
      if(!span) return null;
      plans.push({node:span.node,start:idx-span.start,end:end-span.start,to:String(action.to ?? ''),globalStart:idx});
      cursor=end;
    }
    return plans;
  }

  function patchMessageDomSilently(mesEl, actions, rawBefore){
    const textEl=mesEl?.querySelector?.('.mes_text') || null;
    if(!textEl) return {ok:false};
    const plans=planSilentTextPatch(textEl,actions,rawBefore);
    if(!plans || plans.length!==(actions || []).length) return {ok:false};
    const snapshot=textEl.innerHTML;
    try{
      plans.sort((a,b)=>b.globalStart-a.globalStart).forEach(p=>{
        const value=String(p.node.nodeValue || '');
        p.node.nodeValue=value.slice(0,p.start)+p.to+value.slice(p.end);
      });
      return {ok:true,rollback:()=>{ try{textEl.innerHTML=snapshot;}catch(e){} }};
    }catch(e){
      try{textEl.innerHTML=snapshot;}catch(_){}
      return {ok:false};
    }
  }

  function createMessageVisualGhost(mesEl){
    if(!mesEl?.isConnected) return null;
    try{
      const rect=mesEl.getBoundingClientRect();
      if(rect.bottom<0 || rect.top>(ROOT.innerHeight||DOC.documentElement.clientHeight||0)) return null;
      const ghost=mesEl.cloneNode(true);
      ghost.removeAttribute('id');
      ghost.querySelectorAll?.('[id]').forEach(el=>el.removeAttribute('id'));
      ghost.setAttribute('aria-hidden','true');
      const chatBg=DOC.querySelector('#chat');
      const bg=ROOT.getComputedStyle?.(chatBg || DOC.body)?.backgroundColor || 'transparent';
      Object.assign(ghost.style,{
        position:'fixed',left:rect.left+'px',top:rect.top+'px',width:rect.width+'px',height:rect.height+'px',
        margin:'0',zIndex:'2147483600',pointerEvents:'none',overflow:'hidden',contain:'paint',
        transition:'none',animation:'none',backgroundColor:bg
      });
      ghost.querySelectorAll?.('*').forEach(el=>{el.style.transition='none';el.style.animation='none';});
      (DOC.body || DOC.documentElement).appendChild(ghost);
      return ghost;
    }catch(e){ return null; }
  }

  async function maskedRerenderMessage(target, mesEl, msg){
    const ctx=target.ctx || ROOT.SillyTavern?.getContext?.();
    const viewport=captureChatViewport(mesEl);
    const ghost=createMessageVisualGhost(mesEl);
    const refreshFns=[ctx?.updateMessageBlock,ROOT.updateMessageBlock].filter(fn=>typeof fn==='function');
    let rendered=false;
    for(const fn of refreshFns){
      try{
        await Promise.resolve(fn.call(ctx||ROOT,target.idx,msg,{rerenderMessage:true}));
        rendered=true;
        break;
      }catch(e){console.warn('[Clawed purify] masked updateMessageBlock:',e);}
    }
    const live=getLiveMessageElement(target.idx,mesEl);
    stabilizeChatViewport(viewport,live);
    const raf=ROOT.requestAnimationFrame?.bind(ROOT) || (fn=>ccSetTimeout(fn,16));
    raf(()=>raf(()=>{try{ghost?.remove();}catch(e){}}));
    return rendered;
  }

  async function persistPurifiedMessage(target, mesEl, newText, actions) {
    const ctx = target.ctx || ROOT.SillyTavern?.getContext?.();
    const oldText=String(target.chat[target.idx].mes || '');
    const msg=target.chat[target.idx];
    const liveMes=getLiveMessageElement(target.idx,mesEl);
    const viewport=captureChatViewport(liveMes);
    const domPatch=patchMessageDomSilently(liveMes,actions || [],oldText);
    try{
      target.chat[target.idx].mes=newText;
      // 常规路径完全不调用 updateMessageBlock，也不广播 MESSAGE_RENDERED：只改现有文本节点并保存，楼层不会拆建。
      if(domPatch.ok) stabilizeChatViewport(viewport,liveMes);
      else if(!(await maskedRerenderMessage(target,liveMes,msg))) throw new Error('无法静默更新当前楼层 DOM');
      const saveFn=typeof ROOT.saveChatConditional==='function' ? ROOT.saveChatConditional.bind(ROOT)
        : typeof ctx?.saveChatConditional==='function' ? ctx.saveChatConditional.bind(ctx)
        : typeof ctx?.saveChat==='function' ? ctx.saveChat.bind(ctx) : null;
      if(!saveFn) throw new Error('未找到 SillyTavern 保存函数');
      await Promise.resolve(saveFn());
      if(String(target.chat[target.idx]?.mes || '')!==String(newText)) throw new Error('保存后内存回读不一致');
      return {ok:true,silent:!!domPatch.ok};
    }catch(e){
      target.chat[target.idx].mes=oldText;
      if(domPatch.ok) domPatch.rollback?.();
      else await maskedRerenderMessage(target,getLiveMessageElement(target.idx,liveMes),msg);
      stabilizeChatViewport(viewport,getLiveMessageElement(target.idx,liveMes));
      console.warn('[Clawed purify] save rollback:',e);
      return {ok:false,error:e?.message || String(e)};
    }
  }

  async function applyToChat(map, opts={}) {
    const quiet=!!opts.quiet;
    const returnDetails=!!opts.returnDetails;
    const done=(ok,extra={})=>returnDetails?Object.assign({ok:!!ok},extra):(ok===true);
    map=normalizePurifyMap(map);
    if(!Object.keys(map).length){if(!quiet)showBubble('没有可应用的改写结果');return done(false,{reason:'empty-map',applied:[],rejected:[]});}
    if(!lastPurify){if(!quiet)showBubble('找不到净化目标');return done(false,{reason:'no-target',applied:[],rejected:[]});}
    const mesEl=lastPurify.mesEl || getMesElByIndex(lastPurify.idx);
    const target=(mesEl?getTargetMessageFromEl(mesEl):null)||getTargetMessageByIndex(lastPurify.idx);
    if(!target?.chat?.[target.idx]){if(!quiet)showBubble('找不到 ST 原始消息，未写入');return done(false,{reason:'missing-message',applied:[],rejected:[]});}
    const rawBefore=String(target.chat[target.idx].mes || '');
    symbolGuardBlocked=0;
    const applied=applyMapToContext(rawBefore,map);
    if(!applied.applied.length){
      lastApplyGuardFailure={map:Object.fromEntries(applied.rejected.map(x=>[x.id,x])),blocked:applied.rejected.length,round:purifyRoundInfo?.round||1,ts:Date.now(),text:lastPurify.text,found:[...(lastPurify.found||[])]};
      lastPurifyMap=null;purifyCleanText='';updatePurifyArea();
      if(!quiet) showBubble('🛡️ 所有改写均因正文已变化、符号或重复风险被拒绝；原文未动。',9000);
      return done(false,{reason:'all-rejected',applied:[],rejected:applied.rejected});
    }
    console.log('[Clawed净化写回] 楼层',target.idx,'成功',applied.applied.length,'条，拒绝',applied.rejected.length,'条');
    const saved=await persistPurifiedMessage(target,target.mesEl||mesEl,applied.text,applied.applied);
    if(!saved.ok){if(!quiet)showBubble('写入失败，已回滚原文：'+saved.error,10000);return done(false,{reason:'save-failed',error:saved.error,applied:[],rejected:applied.rejected});}
    markAutoPurifyWrite(target.idx,applied.text);
    lastPurify=null;lastPurifyMap=null;purifyCleanText='';purifyRoundInfo=null;lastApplyGuardFailure=null;
    if(applied.rejected.length) rescanPurifyTarget(target.idx,target.mesEl||mesEl);
    else { updatePurifyArea(); $pbadge.classList.remove('has-count'); }
    if(!quiet){
      const tail=applied.rejected.length?'；另有 '+applied.rejected.length+' 条失败项未写入':'。';
      showBubble('✓ 已逐条写入并调用酒馆保存，共 '+applied.applied.length+' 条'+tail,8000);
    }
    return done(true,{reason:'ok',idx:target.idx,rawBefore,rawAfter:applied.text,applied:applied.applied,rejected:applied.rejected});
  }

