  function getPresetPromptContents(){
    try{
      const ctx = ROOT.SillyTavern?.getContext?.();
      const prompts = ctx?.chatCompletionSettings?.prompts
        || ctx?.oaiSettings?.prompts
        || ROOT.oai_settings?.prompts
        || ROOT.promptManager?.serviceSettings?.prompts
        || [];
      const map = new Map();
      (Array.isArray(prompts) ? prompts : []).forEach(p => {
