  function getActiveStyleCanon(){
    try{
      const entries = getActivePresetEntriesLite().filter(x => STYLE_NAME_RE.test(x.name));
      if(!entries.length) return '';
      const contents = getPresetPromptContents();
      if(!contents.size) return '';
      const parts = [];
      let budget = 1600; // 控制 token：全部文风正文合计不超过 ~1600 字
      for(const e of entries){
        const c = (contents.get(String(e.identifier)) || '').trim();
        if(!c) continue;
        const slice = c.slice(0, Math.min(600, budget));
        if(!slice) break;
        parts.push('【' + e.name + '】\n' + slice + (c.length > slice.length ? '……' : ''));
        budget -= slice.length;
        if(budget <= 0) break;
      }
      return parts.join('\n\n');
    }catch(e){ return ''; }
  }

  function makePurifyStyleSample(text, hitItems){
    const s = String(text || '').replace(/<[^>]+>/g, '');
    if(!s) return '';
    const keys = (hitItems || []).map(x => x.key).filter(Boolean);
    let idx = keys.length ? s.indexOf(keys[0]) : -1;
    if(idx < 0) idx = Math.max(0, s.length - 900);
    const start = Math.max(0, idx - 420);
    const end = Math.min(s.length, idx + 720);
    return s.slice(start, end).trim();
  }

  function buildPurifyStyleGuide(text, hitItems){
    const hint = getActiveWritingStyleHint();
    const canon = getActiveStyleCanon();
    const sample = makePurifyStyleSample(text, hitItems);
    return [
