  function aiErrorText(d, status){
    return String(d?.error?.message || d?.error?.code || d?.message || ('HTTP ' + status));
  }
  function aiResponseText(d){
    const content = d?.choices?.[0]?.message?.content;
    if(typeof content === 'string') return content.trim();
    if(Array.isArray(content)) return content.map(x => typeof x === 'string' ? x : (x?.text || x?.content || '')).join('').trim();
    return String(d?.output_text || '').trim();
  }
  function aiReasoningText(d){
    const msg = d?.choices?.[0]?.message || {};
    return String(msg.reasoning_content || msg.reasoning || msg.analysis || '').trim();
  }
  function extractJsonFromText(text){
    const s = String(text || '');
    const starts = [];
    for(let i=0;i<s.length;i++) if(s[i] === '{') starts.push(i);
    for(let si=starts.length-1;si>=0;si--){
      const start=starts[si]; let depth=0, quoted=false, escaped=false;
      for(let i=start;i<s.length;i++){
        const ch=s[i];
        if(quoted){
          if(escaped) escaped=false;
          else if(ch === '\\') escaped=true;
          else if(ch === '"') quoted=false;
          continue;
        }
        if(ch === '"'){ quoted=true; continue; }
        if(ch === '{') depth++;
        else if(ch === '}' && --depth === 0){
          const candidate=s.slice(start,i+1);
          try{
            const obj=JSON.parse(candidate);
            if(obj && typeof obj === 'object' && !Array.isArray(obj)) return candidate;
          }catch(e){}
          break;
        }
      }
    }
    return '';
  }
  function needsCompletionTokenParam(model){
    return /^(?:o[1-9]|gpt-5)(?:$|[-.])/i.test(String(model || ''));
  }
  function isOpenAiReasoningModel(model){
    return /^(?:o[1-9]|gpt-5)(?:$|[-.])/i.test(String(model || ''));
