    return /(^|\/\/)(?:api\.)?openai\.com(?:\/|$)/i.test(String(url || ''));
  }
  function isTokenLimitEmptyResponse(d){
    const choice = d?.choices?.[0] || {};
    const finish = String(choice.finish_reason || '').toLowerCase();
    return finish === 'length' || finish === 'max_tokens' || finish === 'content_filter';
  }
  function isThinkingParamError(msg){
    return /reasoning_effort|thinking|enable_thinking|chat_template_kwargs|unsupported parameter|unknown parameter|unrecognized|invalid parameter/i.test(String(msg || ''));
  }
  function isQwenThinkingModel(model){
    return /(?:^|[/_-])qwen3(?:\.5)?(?:$|[/_.-])/i.test(String(model || ''));
