  async function callAI(msgs,oKey,oUrl,oModel,maxTk,opts){
    const k = oKey || cfg.openaiKey;
    const base = normalizeApiBaseUrl(oUrl || cfg.aiBaseUrl);
    let m = resolveAiModel(base, oModel || cfg.aiModel);
    const options = opts || {};
    const tokenLimit = options.omitTokenLimit ? null : (maxTk || 8000);
    lastAiError = '';
    if(!k){ lastAiError = 'missing_api_key'; return null; }
    if(!m){ lastAiError = 'missing_model：请先点击获取模型或手动填写模型名'; return null; }
    try{
      const request = async (tokenField, structured, thinkingMode) => {
        const body = {model:m,messages:msgs};
        if(tokenField && Number.isFinite(tokenLimit) && tokenLimit > 0) body[tokenField] = tokenLimit;
        if(structured) body.response_format = {type:'json_object'};
        if(thinkingMode === 'openai-minimal') body.reasoning_effort = 'minimal';
        if(thinkingMode === 'openai-low') body.reasoning_effort = 'low';
        if(thinkingMode === 'deepseek') body.thinking = {type:'disabled'};
        if(thinkingMode === 'qwen'){
          body.enable_thinking = false;
          body.thinking_budget = 64;
        }
        if(thinkingMode === 'qwen-template'){
          body.chat_template_kwargs = {enable_thinking:false};
          body.thinking_budget = 64;
        }
        const r = await fetch(apiEndpoint(base, '/chat/completions'), {
          method:'POST',
          headers:{'Content-Type':'application/json','Authorization':'Bearer ' + k},
          body:JSON.stringify(body)
        });
        const d = await r.json().catch(()=>({}));
        return {r,d};
      };

      let tokenField = options.omitTokenLimit ? null : (needsCompletionTokenParam(m) ? 'max_completion_tokens' : 'max_tokens');
      let structured = !!options.jsonMode;
      const qwenThinking = !!options.disableThinking && isQwenThinkingModel(m);
      const openAiReasoning = !!options.disableThinking && isOpenAiReasoningModel(m) && (isOpenAiBase(base) || /^(?:o[1-9]|gpt-5)(?:$|[-.])/i.test(m));
      let thinking = !options.disableThinking ? ''
        : qwenThinking ? 'qwen'
        : (isDeepSeekBase(base) || /deepseek/i.test(m)) ? 'deepseek'
        : openAiReasoning ? 'openai-minimal'
        : '';

      let {r,d} = await request(tokenField, structured, thinking);
      let requestError = !r.ok ? aiErrorText(d,r.status) : '';

      if(!r.ok && /max_(?:completion_)?tokens/i.test(requestError)){
        tokenField = tokenField === 'max_tokens' ? 'max_completion_tokens' : (tokenField === 'max_completion_tokens' ? null : 'max_tokens');
        ({r,d} = await request(tokenField, structured, thinking));
        requestError = !r.ok ? aiErrorText(d,r.status) : '';
      }

      if(!r.ok && thinking && isThinkingParamError(requestError)){
        if(thinking === 'qwen') thinking = 'qwen-template';
        else if(thinking === 'openai-minimal') thinking = 'openai-low';
        else thinking = '';
        ({r,d} = await request(tokenField, structured, thinking));
        requestError = !r.ok ? aiErrorText(d,r.status) : '';
      }
      if(!r.ok && thinking === 'openai-low' && isThinkingParamError(requestError)){
        thinking = '';
        ({r,d} = await request(tokenField, structured, thinking));
        requestError = !r.ok ? aiErrorText(d,r.status) : '';
      }

      if(!r.ok && structured && /response_format|json_object|unsupported parameter|unknown parameter|unrecognized/i.test(requestError)){
        structured = false;
        ({r,d} = await request(tokenField, structured, thinking));
        requestError = !r.ok ? aiErrorText(d,r.status) : '';
      }

      if(!r.ok && options.relaxed){
        // 兜底：部分 OpenAI-compatible 网关会把可选参数报成 Unknown error。
        // relaxed 模式直接退回最小请求体，并且不发送 max_tokens / max_completion_tokens。
        structured = false;
        thinking = qwenThinking ? 'qwen-template' : '';
        tokenField = null;
        ({r,d} = await request(tokenField, structured, thinking));
      }

      if(!r.ok){
        lastAiError = aiErrorText(d,r.status);
        console.warn('[Clawed AI]', lastAiError, d);
        return null;
      }

      let out = aiResponseText(d);

      if(!out && qwenThinking && thinking !== 'qwen-template'){
        // Some Qwen gateways accept but ignore enable_thinking. Try the vLLM
        // chat-template switch when the response contains only reasoning.
        ({r,d} = await request(tokenField, false, 'qwen-template'));
        if(r.ok) out = aiResponseText(d);
      }

      if(!out && options.acceptReasoningJson){
        const recovered = extractJsonFromText(aiReasoningText(d));
        if(recovered){
          lastAiError = '';
          return recovered;
        }
      }

      if(!out && options.relaxed && tokenField && isTokenLimitEmptyResponse(d)){
        // OpenAI 推理模型的 max_completion_tokens 会包含隐藏思考 token。
        // 如果 finish_reason=length 但正文为空，说明预算被思考吃完了，立刻不带 token 限制重试一次。
        tokenField = null;
        structured = false;
        ({r,d} = await request(tokenField, structured, thinking));
        if(r.ok) out = aiResponseText(d);
        if(!out && options.acceptReasoningJson){
          const recovered = extractJsonFromText(aiReasoningText(d));
          if(recovered){ lastAiError = ''; return recovered; }
        }
      }

      if(!out){
        const choice = d?.choices?.[0] || {};
        const reason = choice.finish_reason ? ', finish_reason=' + choice.finish_reason : '';
        const thought = choice.message?.reasoning_content ? ', 已产生思考但未输出正文' : '';
        const tokenHint = isTokenLimitEmptyResponse(d) ? ', 疑似输出/思考 token 预算被截断' : '';
        lastAiError = 'empty_response' + reason + thought + tokenHint;
      }
      return out || null;
    }catch(e){
      const em = e?.message || String(e);
      lastAiError = (isDoubaoBase(base) && /fetch|network|cors/i.test(em))
        ? '豆包接口跨域限制（CORS），建议改用酒馆自带的API代理通道'
        : em;
      console.warn('[Clawed AI request]', e);
      return null;
    }
  }
