  // ─── 净化 AI：只替换检测到的词/句，逐词打点 ──────────────────

  function collectWordContextSentences(text, word, limit) {
    const s = String(text || '');
    const w = String(word || '');
    const out = [];
    if(!s || !w) return out;
    let from = 0;
    const max = limit || 6;
    while (from < s.length && out.length < max) {
      const idx = s.indexOf(w, from);
      if(idx < 0) break;
      const sent = expandToSentence(s, idx, idx + w.length) || w;
      if(sent && !out.includes(sent)) out.push(sent);
      from = idx + Math.max(1, w.length);
    }
    return out;
  }

  function collectWordHitUnits(text, word, limit, occurrences) {
    const s = String(text || '');
    const w = String(word || '');
    const out = [];
    if(!s || !w) return out;
    const indexes = Array.isArray(occurrences) ? occurrences : getLiteralWordOccurrences(s,w,'custom');
    const max = limit || 50;
    for(const idx of indexes.slice(0,max)){
      const unit = expandToClauseBounds(s, idx, idx + w.length);
      if(unit.text) out.push({...unit, hitStart:idx, hitEnd:idx+w.length});
    }
    return out;
  }

  function buildPurifyHitItems(text, found, doc) {
    found = normalizeActiveFound(found);
    const source=String(text || '');
    const document=doc || lastPurify?.doc || null;
    const raw=[];
    const wordMatches = getPurifyWordMatches(source).filter(item => found.includes(item.word));
    wordMatches.forEach(item => {
      const kind = item.type === 'anatomy' ? 'anatomy' : 'word';
      const label = kind === 'anatomy' ? '解剖/专业词：' + item.word : '八股词：' + item.word;
      collectWordHitUnits(source,item.word,100,item.occurrences).forEach(unit => {
        const loc=locatePurifyContext(document,unit.start,unit.end);
        if(!loc) return;
        raw.push({kind,key:unit.text,unitStart:unit.start,unitEnd:unit.end,contextIndex:loc.contextIndex,localStart:loc.start,localEnd:loc.end,labels:[label],instructions:[item.instruction || getWordInstruction(item.word,kind)],hitWords:[item.word],occurrenceWeight:1});
      });
    });
    const patLabels=found.filter(f=>f.startsWith('【')).map(f=>f.slice(1,-1));
    getAllPatternRules().filter(p=>patLabels.includes(p.label)).forEach(p => {
      collectPatternUnitsForRule(source,p).forEach(unit => {
        const loc=locatePurifyContext(document,unit.start,unit.end);
        if(!loc) return;
        raw.push({kind:'pattern',key:unit.text,unitStart:unit.start,unitEnd:unit.end,contextIndex:loc.contextIndex,localStart:loc.start,localEnd:loc.end,labels:['句式：'+p.label],instructions:[getPatternInstruction(p.label)],hitWords:[],occurrenceWeight:1});
      });
    });
    raw.sort((a,b)=>a.contextIndex-b.contextIndex || a.localStart-b.localStart || b.localEnd-a.localEnd);
    const merged=[];
    for(const hit of raw){
      const prev=merged[merged.length-1];
      if(prev && prev.contextIndex===hit.contextIndex && hit.localStart < prev.localEnd && hit.localEnd > prev.localStart){
        const start=Math.min(prev.localStart,hit.localStart), end=Math.max(prev.localEnd,hit.localEnd);
        const seg=document?.segments?.find(x=>x.contextIndex===hit.contextIndex);
        prev.localStart=start; prev.localEnd=end;
        prev.unitStart=(seg?.globalStart || 0)+start; prev.unitEnd=(seg?.globalStart || 0)+end;
        prev.key=source.slice(prev.unitStart,prev.unitEnd);
        if(hit.kind==='pattern') prev.kind='pattern';
        else if(prev.kind!=='pattern' && hit.kind==='anatomy') prev.kind='anatomy';
        hit.labels.forEach(x=>{if(!prev.labels.includes(x))prev.labels.push(x)});
        hit.instructions.forEach(x=>{if(x&&!prev.instructions.includes(x))prev.instructions.push(x)});
        hit.hitWords.forEach(x=>{if(x&&!prev.hitWords.includes(x))prev.hitWords.push(x)});
        prev.occurrenceWeight=(prev.occurrenceWeight||1)+(hit.occurrenceWeight||1);
      }else merged.push({...hit});
    }
    return merged.map((item,i)=>{
      const id='hit_'+item.contextIndex+'_'+item.localStart+'_'+item.localEnd+'_'+i;
      return {...item,id,label:item.labels.join(' + '),instruction:item.instructions.join('\n')};
    });
  }

  function getPurifyStats(text, found, doc){
    const hits=buildPurifyHitItems(text,found,doc);
    return {hits, occurrenceCount:hits.reduce((n,x)=>n+(x.occurrenceWeight||1),0), actionCount:hits.length, ruleCount:normalizeActiveFound(found).length};
  }

  function purifySentenceAround(text, key){
    const s = String(text || '');
    const idx = s.indexOf(key);
    if(idx < 0) return '';
    return expandToSentence(s, idx, idx + String(key || '').length);
  }

  async function callPurifyAi(text, found) {
    found = normalizeActiveFound(found);
    const hitItems = buildPurifyHitItems(text, found);
    if (!hitItems.length) return null;

    const sys = getPurifySystemPrompt();
    const styleGuide = buildPurifyStyleGuide(text, hitItems);
    const selectedModel = resolveAiModel(cfg.aiBaseUrl,cfg.aiModel);
    const isQwen = isQwenThinkingModel(selectedModel);
    const itemLines = hitItems.map((item, i) => {
      const hitWords = (item.hitWords || []).filter(Boolean);
      const isStructural = isStructuralPurifyItem(item);
      const modeGuide = isStructural ? [
        'mode: rewrite（结构句式型）。允许重写 source 这个最小分句/句子，但不得越界到 source 外。',
        '输出格式：hit_id 对应的 value 必须是 {"mode":"rewrite","to":"改写后的同一最小句/分句"}。',
        '必须删除 rule 指向的结构骨架（如“不是A，而是B”“与其说A不如说B”“不像A更像B”），改成肯定、自然、有文学性的表达。',
        'to 必须保留 source 里的引号、括号、星号、反引号等成对符号；逗号、顿号、句号、问号、叹号、冒号、分号、省略号、破折号可以为句意通顺做必要调整，但必须用得正确，不能只靠改标点交差。若无法做到，省略该 hit_id。'
      ] : [
        'mode: local（词语/短语型）。不要整句重写，只改 hit_word 及其紧邻的小片段。',
        '输出格式：hit_id 对应的 value 必须是 {"mode":"local","edits":[{"from":"原文中连续片段","to":"结合语境后的替换片段"}]}。',
        'from 可以略大于 hit_word（例如“颧骨上”而不是只写“颧骨”），但必须是 source 里真实存在的连续文字；to 要结合语境，不要机械同义词替换。',
        'edits 的 from/to 不要包含逗号、句号、问号、引号、括号、星号等标点符号；标点由客户端保留原文，不能交给你改。'
      ];
      const hardRule = [
        ...modeGuide,
        '只处理 label / rule 指向的问题词、问题片段或病句结构；source 内没有问题的信息、动作、人物、顺序尽量原样保留。',
        '禁止把 source 当成灵感重写，禁止清洗整段，禁止替换 source 外的上下文。',
        '若只替换/删除命中词会让分句不通，允许在命中词前后很小范围顺句；但禁止把原句改成全新表达。',
        '风格必须贴合 style_hint / style_sample，但风格只用于对齐语气，不得借机润色无关内容。',
        '禁止返回等于原文的无效改写；没有有效改写就不要输出这个 hit_id。',
        '解剖/医学词改写不得造词，不得新增原文没有的身体部位；宁可少改，也不要写出“颧头/颧弧/下颌线绷成弧度”这类怪句。'
      ].filter(Boolean).join(' ');
      return [
        `${i+1}. type: ${isStructural ? 'structural_rewrite' : 'local_edit'}`,
        `label: ${item.label}`,
        hitWords.length ? `hit_word: ${hitWords.join('、')}` : '',
        `hit_id: ${item.id}`,
        `source: ${JSON.stringify(item.key)}`,
        hardRule,
        `rule: ${item.instruction}`
      ].filter(Boolean).join('\n');
    }).join('\n\n');
    const styleBlock = styleGuide ? ('\n\n【风格锚定】\n' + styleGuide + '\n') : '';
    const disabledGuide = buildDisabledProtectionGuide(text);
    const disabledBlock = disabledGuide ? ('\n\n【用户已停用/保护项】\n' + disabledGuide + '\n') : '';
    const formatGuide = [
      '按每条 rule 处理对应 hit_id 的 source。只输出 JSON 对象，不要解释，不要 Markdown。',
      'JSON 顶层格式：{"hit_...":{"mode":"local","edits":[{"from":"...","to":"..."}]}, "hit_...":{"mode":"rewrite","to":"..."}}。',
      '词语/短语型必须返回 local edits；结构句式型才允许 rewrite。',
      '没有列出的 hit_id 绝对不要输出；无法有效改写的 hit_id 直接省略。',
      '用户已停用的词条/句式不能作为净化依据；若 source 中含有 protected_words，必须原样保留这些词。'
    ].join('\n');
    const userMsg = (isQwen ? '/no_think\n' : '') + formatGuide + styleBlock + disabledBlock + '\n\n' + itemLines;
    const messages = isQwen
      ? [{role:'user',content:sys + '\n\n' + userMsg}]
      : [{role:'system',content:sys},{role:'user',content:userMsg}];
    let result = await callAI(messages, null, null, null, null, {jsonMode:true,disableThinking:true,omitTokenLimit:true,relaxed:true,acceptReasoningJson:true});
    if(!result && /^empty_response/.test(lastAiError)){
      const compact = '立即输出 JSON，不要思考，不要解释。词语型用 {"mode":"local","edits":[{"from":"原文连续片段","to":"替换片段"}]} 且不动标点；结构型用 {"mode":"rewrite","to":"改写后的同一最小句"}，可为通顺必要调整行文标点，但引号/括号/星号等成对符号不能动，做不到就省略：\n' + hitItems.map(x => x.id + ' // ' + JSON.stringify(x.key) + ' // ' + x.label + ' // ' + x.instruction).join('\n');
      result = await callAI(isQwen ? [{role:'user',content:'/no_think\n' + compact}] : [{role:'system',content:sys},{role:'user',content:compact}], null, null, null, null, {disableThinking:true,omitTokenLimit:true,relaxed:true,acceptReasoningJson:true});
    }
    return result;
  }


  const BAD_ANATOMY_REWRITE_RE = /(颧头|颧弧|颧侧|颧面|颧部|颧峰|颧线|骨线|骨面|骨弧|肋线|肋面|锁骨线|脊线|胯线|髋线|耻骨线|下颌线绷成的?弧度|绷成的?弧度)/;
  const NEW_ANATOMY_TERMS = [...new Set([...FORB_ANATOMY, '下颌线','下颌','颧头','颧弧','颧侧','颧面','颧部','颧峰','颧线','骨线','骨面','骨弧','肋线','肋面','锁骨线','脊线','胯线','髋线','耻骨线'])];

  function getHitWordFromItem(item){
    const info = String((item?.label || '') + '\n' + (item?.instruction || ''));
    const m = info.match(/命中词：([^。\n]+)[。\n]?/);
    if(m && m[1]) return m[1].trim();
    const m2 = info.match(/(?:八股词|解剖\/专业词)：([^\n]+)/);
    if(m2 && m2[1]) return m2[1].trim();
    return '';
  }

  function looksLikeAnatomyItem(item){
    const info = String((item?.label || '') + '\n' + (item?.instruction || ''));
    return /解剖|医学|专业词|anatomy|颧骨|颧弓|肋骨|肋下|锁骨|肩胛|肩胛骨|腰椎|颈椎|胸椎|尾椎|脊柱|脊椎|椎骨|骶骨|胯骨|髋骨|髂骨|坐骨|耻骨|喉结|脉搏|鼓膜|虹膜|头骨|颅骨|额骨|眉骨|鼻骨|颌骨|腕骨|股骨|胫骨|腓骨|髌骨/.test(info);
  }

  function validatePurifyValue(realKey, val, item){
    const original = String(realKey || '');
    const value = String(val || '').trim();
    if(!looksLikeAnatomyItem(item)) return {ok:true, val:value};
    if(BAD_ANATOMY_REWRITE_RE.test(value)) return {ok:false, val:''};
    for(const term of NEW_ANATOMY_TERMS){
      if(value.includes(term) && !original.includes(term)) return {ok:false, val:''};
    }
    const hit = getHitWordFromItem(item);
    if((hit === '颧骨' || original.includes('颧骨')) && /颧/.test(value)) return {ok:false, val:''};
    return {ok:true, val:value};
  }


  // v5.5.3：命中 ID 定点改写 + 客户端逐条安全写回。
  // 词语型不再让 AI 返回整句，而是让 AI 给 from/to 局部 edits；脚本在原 key 上本地拼回，标点永远来自原文。
  const FULL_PUNCT_RE = /[，,、；;：:。！!？?…—·“”‘’"'「」『』《》（）()\[\]【】{}<>〈〉《》*`]/g;
  const PROTECTED_SYMBOL_RE = /[“”‘’"'「」『』《》（）()\[\]【】{}<>〈〉*`]/g;
  function punctSeq(s){ return (String(s || '').match(FULL_PUNCT_RE) || []).join(''); }
  function protectedSymbolSeq(s){ return (String(s || '').match(PROTECTED_SYMBOL_RE) || []).join(''); }
  function stripAllPunct(s){ return String(s || '').replace(FULL_PUNCT_RE, '').replace(/\s+/g, ''); }
  function punctSeqChanged(before, after){ return punctSeq(before) !== punctSeq(after); }
  function protectedSymbolSeqChanged(before, after){ return protectedSymbolSeq(before) !== protectedSymbolSeq(after); }
  function punctuationQualityBroken(before, after){
    const b=String(before || '').trim(), t=String(after == null ? before : after).trim();
    if(!t) return false;
    const badStart=/^[，,、；;：:。！!？?]/.test(t);
    if(badStart && !/^[，,、；;：:。！!？?]/.test(b)) return true;
    const trailing=t.match(/[，,、；;：:]$/)?.[0] || '';
    const oldTrailing=b.match(/[，,、；;：:]$/)?.[0] || '';
    if(trailing && trailing!==oldTrailing) return true;
    if(/[，,、；;：:]{2,}/.test(t)) return true;
    if(/[。！？!?]{3,}/.test(t)) return true;
    if(/[，,、；;：:]\s*[。！？!?]/.test(t)) return true;
    if(/[。！？!?]\s*[，,、；;：:]/.test(t)) return true;
    return false;
  }
  function getDisabledPatternRules(){ return FORB_PATS.filter(p=>isBuiltinPatternDisabled(p.label)); }
  function patternMatchCount(text,p){
    const re=cloneRegexGlobal(p.re); let count=0,m;
    while((m=re.exec(String(text || '')))){count++;if(!m[0])re.lastIndex++;}
    return count;
  }
  function violatesDisabledPatternProtection(before,after){
    for(const p of getDisabledPatternRules()){
      const b=patternMatchCount(before,p), a=patternMatchCount(after,p);
      if(b>0 && a<b) return true;
    }
    return false;
  }
  function hasHardPunct(s){ return FULL_PUNCT_RE.test(String(s || '')); }
  function resetHardPunctRe(){ try { FULL_PUNCT_RE.lastIndex = 0; } catch(e) {} }
  function containsHardPunct(s){ resetHardPunctRe(); const ok = FULL_PUNCT_RE.test(String(s || '')); resetHardPunctRe(); return ok; }
  function isStructuralPurifyItem(item){
    return item?.kind === 'pattern';
  }
  function normalizeAiPayloadMap(rawMap){
    const src = rawMap && typeof rawMap === 'object' && !Array.isArray(rawMap) ? rawMap : {};
    const out = {};
    Object.entries(src).forEach(([k, v]) => {
      if(!k || !v || typeof v !== 'object' || Array.isArray(v)) return;
      out[String(k)] = v;
    });
    return out;
  }
  function firstReplaceOnce(text, from, to){
    text = String(text || ''); from = String(from || ''); to = String(to == null ? '' : to);
    const idx = text.indexOf(from);
    if(idx < 0) return null;
    return text.slice(0, idx) + to + text.slice(idx + from.length);
  }
  function buildCandidateFromLocalEdits(realKey, payload, item){
    let edits = [];
    if(Array.isArray(payload?.edits)) edits = payload.edits;
    else if(payload && typeof payload === 'object' && ('from' in payload || 'to' in payload)) edits = [payload];
    if(!edits.length) return '';
    let next = String(realKey || '');
    const hitWords = (item?.hitWords || []).filter(Boolean);
    for(const ed of edits){
      const from = String(ed?.from || '');
      const to = ed?.to == null ? '' : String(ed.to);
      if(!from) return '';
      if(!next.includes(from)) return '';
      // 词语型 edits 不接管标点；一旦 from/to 包含硬标点，说明模型又想动边界，丢弃。
      if(containsHardPunct(from) || containsHardPunct(to)) return '';
      if(hitWords.length && !hitWords.some(w => from.includes(w))){
        // 允许医学词做“颧骨上”这类扩展，但必须覆盖至少一个命中词。
        return '';
      }
      const replaced = firstReplaceOnce(next, from, to);
      if(replaced == null) return '';
