  }
  function getRewriteCandidate(realKey, payload){
    return payload && payload.mode === 'rewrite' && typeof payload.to === 'string' ? payload.to : '';
  }
  function passesPurifyQualityGate(realKey, safeVal, item, allowDelete){
    const original = String(realKey || '');
    const value = String(safeVal || '').trim();
    const structural = isStructuralPurifyItem(item);
    if(!value) return !!allowDelete;
    if(value === original || value === original.trim()) return false;
    // 词语型仍锁死全部标点；结构句式型允许调整行文标点，但不能破坏成对/标记符号。
    if(structural ? protectedSymbolSeqChanged(original, value) : punctSeqChanged(original, value)) return false;
    if(punctuationQualityBroken(original, value)) return false;
    // 纯标点/空白变化 = 无效。
    if(stripAllPunct(value) === stripAllPunct(original)) return false;
    if(violatesDisabledWordProtection(original, value) || violatesDisabledPatternProtection(original, value)) return false;
    const checked = validatePurifyValue(original, value, item);
    if(!checked.ok) return false;
    const checkedVal = String(checked.val || '').trim();
    if(!checkedVal) return !!allowDelete;
    if(structural ? protectedSymbolSeqChanged(original, checkedVal) : punctSeqChanged(original, checkedVal)) return false;
    if(punctuationQualityBroken(original, checkedVal)) return false;
    if(stripAllPunct(checkedVal) === stripAllPunct(original)) return false;
    if(violatesDisabledWordProtection(original, checkedVal) || violatesDisabledPatternProtection(original, checkedVal)) return false;
    const fullText = String(lastPurify?.text || '');
    let dupWindow = false;
    for(let i = 0; i + 8 <= checkedVal.length; i++){
      const win = checkedVal.slice(i, i + 8);
      if(!original.includes(win) && fullText.includes(win)){ dupWindow = true; break; }
    }
    if(dupWindow) return false;
    if(checkedVal.length > Math.max(original.length * 1.55, original.length + 32)) return false;
    if(original.length > 20 && checkedVal.length < Math.max(4, original.length * 0.20) && !allowDelete) return false;
    if(checkedVal.includes(original) && checkedVal.length > original.length + 4) return false;
    return checkedVal;
  }
  function filterPurifyMap(rawMap, text, found) {
    const map = normalizeAiPayloadMap(rawMap);
    const hitItems = buildPurifyHitItems(text, found, lastPurify?.doc);
    const byId = new Map(hitItems.map(item => [item.id, item]));
    const out = {};
    Object.entries(map).forEach(([id, payload]) => {
      const item=byId.get(String(id || ''));
      if(!item) return;
      const realKey=item.key;
      const info=String((item.label || '')+'\n'+(item.instruction || ''));
      const allowDelete=/无功能呼吸叹气|整句完全是无功能废句/.test(info)
        || /^(?:深吸一口气|轻叹一声|舔了舔嘴唇)[。！？!?]?$/.test(realKey.trim());
      const structural=isStructuralPurifyItem(item);
      let candidate='';
      if(!structural){
        if(!(payload && typeof payload==='object' && payload.mode==='local')) return;
        candidate=buildCandidateFromLocalEdits(realKey,payload,item);
      }else candidate=getRewriteCandidate(realKey,payload);
      const val=String(candidate == null ? '' : candidate).trim();
      if(!val && !allowDelete) return;
      const passed=val ? passesPurifyQualityGate(realKey,val,item,allowDelete) : '';
      if(val && !passed) return;
      const finalValue=val ? String(passed) : '';
      const candidateAction={id:item.id,kind:item.kind,from:realKey,to:finalValue,label:item.label,hitWords:[...(item.hitWords || [])]};
      // 主模型候选先做一次本地复扫：不得把“猛地”换成“突然”，也不得换成另一种新八股句式。
      if(candidateStillHitsOwnRule(candidateAction,finalValue)) return;
      if(candidateIntroducesNewPurifyRule(realKey,finalValue)) return;
      out[item.id]={
        id:item.id,kind:item.kind,contextIndex:item.contextIndex,start:item.localStart,end:item.localEnd,
        from:realKey,to:finalValue,label:item.label,hitWords:[...(item.hitWords || [])]
      };
    });
    return Object.keys(out).length ? out : null;
  }



  // ─── 独立质检：第二模型审核 / 返修候选改写 ──────────────────
  let lastQaError = '';
  function getPurifyQaConnection(){
    const useMain = cfg.purifyQaUseMainApi !== false;
    return {
      useMain,
      key: useMain ? cfg.openaiKey : String(cfg.purifyQaKey || '').trim(),
      base: normalizeApiBaseUrl(useMain ? cfg.aiBaseUrl : (cfg.purifyQaBaseUrl || DEFAULTS.aiBaseUrl)),
      model: String(useMain ? cfg.aiModel : cfg.purifyQaModel || '').trim()
    };
  }
  function isHighRiskPurifyAction(action){
    if(!action) return true;
    if(action.kind === 'pattern' || action.kind === 'anatomy') return true;
    if(protectedSymbolSeq(action.from)) return true;
    const beforeLen=Math.max(1,stripAllPunct(action.from).length);
    const delta=Math.abs(stripAllPunct(action.to).length-beforeLen)/beforeLen;
    if(delta > 0.22) return true;
    if(/“|”|「|」|『|』|\"|'/.test(String(action.from || ''))) return true;
    if((action.hitWords || []).length > 1) return true;
    return false;
  }
  function shouldQaReviewAction(action){
    return cfg.purifyQaScope === 'all' || isHighRiskPurifyAction(action);
  }
  function getPurifyHitItemById(id){
    return (lastPurify?.hitItems || lastPurify?.stats?.hits || buildPurifyHitItems(lastPurify?.text || '',lastPurify?.found || [],lastPurify?.doc)).find(x=>x.id===id) || null;
  }
  function getTargetPatternLabels(action){
    return [...String(action?.label || '').matchAll(/句式：([^+\n]+)/g)].map(m=>m[1].trim()).filter(Boolean);
  }
  function candidateStillHitsOwnRule(action, candidate){
    const s=String(candidate || '');
    for(const w of action?.hitWords || []) if(w && s.includes(w) && !isBuiltinWordDisabled(w)) return true;
    const labels=getTargetPatternLabels(action);
    for(const label of labels){
      const rules=getAllPatternRules().filter(p=>p.label===label);
      if(rules.some(p=>patternHasUsableHit(s,p))) return true;
    }
    return false;
  }
  function candidateIntroducesNewPurifyRule(before, after){
    const oldSet=new Set(normalizeActiveFound(scanForbidden(String(before || ''))));
    const next=normalizeActiveFound(scanForbidden(String(after || '')));
    return next.some(x=>!oldSet.has(x));
  }
  function validateQaCandidate(action, candidate){
    const item=getPurifyHitItemById(action.id) || {
      id:action.id,kind:action.kind,key:action.from,label:action.label,
      hitWords:[...(action.hitWords || [])],instruction:''
    };
    const info=String((item.label || '')+'\n'+(item.instruction || ''));
    const allowDelete=/无功能呼吸叹气|整句完全是无功能废句/.test(info)
      || /^(?:深吸一口气|轻叹一声|舔了舔嘴唇)[。！？!?]?$/.test(String(action.from || '').trim());
    const final=String(candidate == null ? '' : candidate).trim();
    if(!final && !allowDelete) return {ok:false,reason:'empty'};
    const passed=final ? passesPurifyQualityGate(action.from,final,item,allowDelete) : '';
    if(final && !passed) return {ok:false,reason:'client-quality-gate'};
    const normalized=final ? String(passed) : '';
    if(candidateStillHitsOwnRule(action,normalized)) return {ok:false,reason:'target-rule-remains'};
    if(candidateIntroducesNewPurifyRule(action.from,normalized)) return {ok:false,reason:'new-purify-rule'};
    return {ok:true,to:normalized};
