  function normalizeQaDecisionPayload(raw){
    if(!raw || typeof raw!=='object' || Array.isArray(raw)) return {};
    const out={};
    Object.entries(raw).forEach(([id,v])=>{
      if(!id || !v || typeof v!=='object' || Array.isArray(v)) return;
      const status=String(v.status || '').toLowerCase();
      if(!['pass','revise','reject'].includes(status)) return;
      out[String(id)]={status,to:typeof v.to==='string'?v.to:'',issues:Array.isArray(v.issues)?v.issues.map(String):[]};
    });
    return out;
  }
  async function callPurifyQa(actions, repairRound, feedback){
    const conn=getPurifyQaConnection();
    lastQaError='';
    if(!conn.key){lastQaError='missing_qa_api_key';return null;}
    if(!conn.model){lastQaError='missing_qa_model';return null;}
    const selectedModel=resolveAiModel(conn.base,conn.model);
    const isQwen=isQwenThinkingModel(selectedModel);
    const styleGuide=buildPurifyStyleGuide(lastPurify?.text || '',(lastPurify?.hitItems || []).filter(x=>actions[x.id]));
    const feedbackLines=feedback && Object.keys(feedback).length
      ? '\n\n【上一轮客户端拒绝原因】\n'+Object.entries(feedback).map(([id,r])=>id+': '+r).join('\n') : '';
    const items=Object.values(actions).map((a,i)=>[
      `${i+1}. hit_id: ${a.id}`,
      `risk: ${isHighRiskPurifyAction(a)?'high':'low'}`,
      `kind: ${a.kind}`,
      `rule: ${a.label}`,
      `original: ${JSON.stringify(a.from)}`,
      `candidate: ${JSON.stringify(a.to)}`,
      `hit_words: ${(a.hitWords || []).join('、') || '无'}`
    ].join('\n')).join('\n\n');
    const sys=[
      '你是中文小说改写质检员，与生成改写的模型相互独立。',
      '你的任务不是自由润色，而是检查 candidate 是否忠实、自然、没有新八股；有问题时直接给出最小返修。',
      '只输出 JSON 对象，不要解释、Markdown 或代码块。'
    ].join('\n');
    const guide=[
      '逐项检查：',
      '1. 原意、情绪方向、人物、动作、对象、因果和视角是否保持；',
      '2. 是否新增原文没有的心理、动作、环境、道具、意象、身体部位或剧情；',
      '3. 是否仍残留 rule / hit_words 指向的八股；',
      '4. 是否制造新的八股词、模板句式、病句、歧义、重复或怪异表达；',
      '5. 引号、括号、星号、反引号等成对符号必须与 original 一致；',
      '6. 词语型不得擅自改变行文标点；结构型可以为通顺必要调整逗号句号，但不能破坏成对符号；',
      '7. 必须贴合 style_sample，但不得扩大修改范围。',
      '',
      '返回格式：',
      '{"hit_id":{"status":"pass","issues":[]}}',
      '或 {"hit_id":{"status":"revise","to":"返修后的完整最小句/分句","issues":["问题"]}}',
      '或 {"hit_id":{"status":"reject","issues":["无法安全修复的原因"]}}。',
