    const style=styleGuide?'\n\n【风格锚定】\n'+styleGuide:'';
    const user=(isQwen?'/no_think\n':'')+guide+style+feedbackLines+'\n\n【待质检候选】\n'+items;
    const msgs=isQwen?[{role:'user',content:sys+'\n\n'+user}]:[{role:'system',content:sys},{role:'user',content:user}];
    const raw=await callAI(msgs,conn.key,conn.base,selectedModel,null,{jsonMode:true,disableThinking:true,omitTokenLimit:true,relaxed:true,acceptReasoningJson:true});
    if(!raw){lastQaError=lastAiError || 'qa_empty_response';return null;}
    const parsed=parseWordMap(raw);
    if(!parsed){lastQaError='qa_json_parse_failed';return null;}
    return normalizeQaDecisionPayload(parsed);
  }
  async function reviewPurifyMapWithQa(map){
    const normalized=normalizePurifyMap(map);
    if(!cfg.purifyQaEnabled) return {map:normalized,reviewed:0,passed:0,revised:0,rejected:0,failed:false};
    const approved={};
    let pending={};
    Object.values(normalized).forEach(a=>{
      if(shouldQaReviewAction(a)) pending[a.id]=a;
      else approved[a.id]=a;
    });
    const reviewed=Object.keys(pending).length;
    if(!reviewed) return {map:normalized,reviewed:0,passed:0,revised:0,rejected:0,failed:false};
    let passed=0,revised=0,rejected=0,feedback={};
    const maxRounds=Math.max(1,Math.min(2,parseInt(cfg.purifyQaRepairRounds,10)||1));
    for(let round=1;round<=maxRounds && Object.keys(pending).length;round++){
      const decisions=await callPurifyQa(pending,round,feedback);
      if(!decisions){
        rejected += Object.keys(pending).length;
        return {map:Object.keys(approved).length?approved:null,reviewed,passed,revised,rejected,failed:true,error:lastQaError};
      }
      const retry={}, nextFeedback={};
      for(const [id,action] of Object.entries(pending)){
        const d=decisions[id];
        if(!d){
          if(round<maxRounds){retry[id]=action;nextFeedback[id]='质检模型漏掉该 hit_id';}
          else rejected++;
          continue;
        }
        if(d.status==='reject'){rejected++;continue;}
        const candidate=d.status==='revise'?d.to:action.to;
        const gate=validateQaCandidate(action,candidate);
        if(gate.ok){
          approved[id]={...action,to:gate.to,qaStatus:d.status,qaIssues:d.issues || []};
          if(d.status==='revise') revised++; else passed++;
        }else if(round<maxRounds){
          retry[id]={...action,to:candidate};
          nextFeedback[id]=gate.reason+(d.issues?.length?'；'+d.issues.join('；'):'');
        }else rejected++;
      }
      pending=retry; feedback=nextFeedback;
    }
    rejected += Object.keys(pending).length;
    return {map:Object.keys(approved).length?approved:null,reviewed,passed,revised,rejected,failed:false};
  }
  async function maybeReviewPurifyMap(map, label){
