    .cc-btxt{flex:1;min-width:0;max-height:calc(min(50vh,320px) - 22px);overflow-y:auto;font-size:13px;line-height:1.7;color:var(--txt);font-family:'PingFang SC','Microsoft YaHei',sans-serif;word-break:break-word;white-space:pre-wrap;}
    .cc-bx{position:absolute;top:7px;right:7px;background:none;border:none;color:var(--txt3);font-size:11px;cursor:pointer;padding:2px 4px;}
    @keyframes ccIn{from{opacity:0;transform:translateY(8px) scale(.95)}to{opacity:1;transform:translateY(0) scale(1)}}
    @keyframes ccOut{from{opacity:1;transform:translateY(0)}to{opacity:0;transform:translateY(5px) scale(.97)}}
    .cc-aIn{animation:ccIn .26s ease forwards;}.cc-aOut{animation:ccOut .3s ease forwards;}
    @media(max-width:768px){
      #cc-drawer{height:100dvh;border-top-left-radius:18px;border-bottom-left-radius:18px;}
      .cc-dh{padding:11px 12px 9px;}
      .cc-dh-sub{display:none;}
      .cc-tab{padding:12px 2px 10px;font-size:12px;}
      .cc-sec-hd{padding:10px 12px 6px;}
      .cc-sec-act{font-size:12px;padding:4px 7px;}
      .cc-group-hd{padding:13px 12px;gap:8px;}
      .cc-group-name{font-size:15px;}
      .cc-group-cnt{font-size:12px;}
