      .cc-pbtns{gap:8px;padding:8px 12px 12px;}
      .cc-pbtns button,.cc-btns button,label.cc-file,.cc-madd button{min-height:38px;font-size:12px;}
      .cc-mstage{height:46px;}
      .cc-mcats{position:sticky;top:0;z-index:2;background:var(--cb2);padding:8px 12px;}
      .cc-mcat{font-size:12px;padding:8px 2px;}
      .cc-mitem{padding:10px 12px;font-size:13px;}
      .cc-madd{padding:10px 12px calc(12px + env(safe-area-inset-bottom,0px));}
      #cc-chatin{padding:10px 12px calc(10px + env(safe-area-inset-bottom,0px));}
      #cc-bubble{max-width:calc(100vw - 24px);}
    }
    @media(max-width:480px){
      #cc-drawer{width:100vw;max-width:none;border-left:none;border-radius:0;}
      #cc-btn{width:50px;height:50px;border-radius:14px;}
      .cc-dh-title{font-size:15px;}
      .cc-tab{font-size:12px;}
      .cc-mtrack{padding-left:12px;padding-right:12px;}
      .cc-mtitle{font-size:14px;}
    }
    `;
    DOC.head.appendChild(s);
  }

  // ─── DOM ──────────────────────────────────────────────────
  const $btn     = DOC.createElement('div'); $btn.id='cc-btn';
  const $pbadge  = DOC.createElement('div'); $pbadge.id='cc-pbadge';
  const $overlay = DOC.createElement('div'); $overlay.id='cc-overlay';
  const $drawer  = DOC.createElement('div'); $drawer.id='cc-drawer';
  const $bubble  = DOC.createElement('div'); $bubble.id='cc-bubble';
  const $rescue  = DOC.createElement('button'); $rescue.id='cc-rescue-handle';
  [$btn,$overlay,$drawer,$bubble,$rescue].forEach(el=>{ el.dataset.ccOwner=ccOwnerToken; });
  $btn.innerHTML = oImg(34);
  $btn.appendChild($pbadge);
  $rescue.type='button';
  $rescue.innerHTML='🦀';
  $rescue.title='召回 Clawed 面板';
  $rescue.setAttribute('aria-label','召回 Clawed 面板');
  addCleanupListener($overlay,'click',()=>closeDrawer());

  // ─── 日夜主题 ─────────────────────────────────────────────
  function applyTheme(){
    const theme = cfg.theme === 'night' ? 'night' : 'day';
    [$btn,$overlay,$drawer,$bubble,$rescue].forEach(el=>el?.setAttribute?.('data-theme',theme));
    const b=DOC.getElementById('cc-theme-toggle');
    if(b){ b.textContent=theme==='night'?'☀':'☾'; b.title=theme==='night'?'切换到日间橙色版':'切换到夜间黑色版'; }
  }
  function toggleTheme(){ cfg.theme = cfg.theme === 'night' ? 'day' : 'night'; saveCfg(); applyTheme(); }

  // ─── 抽屉构建 ─────────────────────────────────────────────
  let drawerBuilt=false, activeTab='purify';

  function buildDrawer(){
    $drawer.innerHTML=`
      <div class="cc-dh">
        <div style="flex-shrink:0">${oImg(36)}</div>
        <div class="cc-dh-info">
          <div class="cc-dh-title">Clawed</div>
          <div class="cc-dh-sub">清洗 · 音乐 · 聊天 · 陪伴</div>
        </div>
        <button class="cc-theme-btn" id="cc-theme-toggle" title="切换日夜模式">☾</button>
        <button class="cc-dh-x" id="cc-d-x" title="收起侧边栏">✕</button>
      </div>
      <div class="cc-tabbar">
        <button class="cc-tab active" data-tab="purify">🧼 清洗</button>
        <button class="cc-tab" data-tab="chat">💬 聊天</button>
        <button class="cc-tab" data-tab="music">🎵 听歌</button>
        <button class="cc-tab" data-tab="purifyrule">🧹 规则</button>
        <button class="cc-tab" data-tab="settings">⚙️ 设置</button>
      </div>
      <div id="cc-tab-purify" class="cc-tab-pane active"></div>
      <div id="cc-tab-chat" class="cc-tab-pane"></div>
      <div id="cc-tab-music" class="cc-tab-pane"></div>
      <div id="cc-tab-purifyrule" class="cc-tab-pane"></div>
      <div id="cc-tab-settings" class="cc-tab-pane"></div>
    `;
    drawerBuilt=true;
    DOC.getElementById('cc-d-x').onclick=closeDrawer;
    DOC.getElementById('cc-theme-toggle').onclick=toggleTheme;
    applyTheme();
    $drawer.querySelectorAll('.cc-tab').forEach(btn=>{
      btn.addEventListener('click',()=>switchTab(btn.dataset.tab));
    });
    buildPurifyTab();
  }

  function switchTab(tabName){
    activeTab=tabName;
    $drawer.querySelectorAll('.cc-tab').forEach(b=>b.classList.toggle('active',b.dataset.tab===tabName));
    $drawer.querySelectorAll('.cc-tab-pane').forEach(p=>p.classList.toggle('active',p.id==='cc-tab-'+tabName));
    if(tabName==='purify')   refreshPurifyPane();
    if(tabName==='chat')     buildChatTab();
    if(tabName==='music')    buildMusicTab();
    if(tabName==='purifyrule') buildPurifyRuleTab();
    if(tabName==='settings') buildSettingsTab();
  }

  // ── 清洗 Tab ────────────────────────────────────────────────
  let lastPurify=null, purifyCleanText='';
  let purifySilentMode=false; // 全自动清洗期间仅暂停面板重绘/角标闪动；状态气泡仍正常显示

  function buildPurifyTab(){
    const pane=DOC.getElementById('cc-tab-purify'); if(!pane)return;
    if(pane.dataset.built) { updatePurifyArea(); return; }
    pane.dataset.built='1';
    pane.innerHTML=`
      <div class="cc-sec-hd">
        <span class="cc-sec-lbl">自动清洗</span>
        <div style="display:flex;gap:6px;align-items:center;">
          <span class="cc-sec-act" id="cc-scan-ctx-btn" title="扫描本轮 context 内容的八股">⚡ 扫本轮</span>
          <span class="cc-sec-act" id="cc-purify-clr-top" title="清空当前检测结果">清空</span>
        </div>
      </div>
      <div id="cc-purify-area"></div>
      <div id="cc-purify-empty" class="cc-no-entry">
        这里不再抓取/管理预设条目。<br>
        开启「自动请求并写回」后，AI 每轮输出完成、补扫命中或手动扫本轮，都会从首轮开始自动请求、校验并写回；无需打开面板确认。
      </div>
    `;
    DOC.getElementById('cc-scan-ctx-btn').onclick=()=>scanContextMsg();
    DOC.getElementById('cc-purify-clr-top').onclick=()=>clearPurifyState(true);
    updatePurifyArea();
    autoScanLatestContext();
  }

  function refreshPurifyPane(){
    buildPurifyTab();
    updatePurifyArea();
    autoScanLatestContext();
  }

  function updatePurifyArea(){
    const area=DOC.getElementById('cc-purify-area'); if(!area)return;
    if(purifySilentMode){ try{$pbadge.classList.remove('has-count');}catch(e){} return; }
    const empty=DOC.getElementById('cc-purify-empty');
    if(!lastPurify||!lastPurify.found?.length){area.style.display='none'; if(empty) empty.style.display=''; $pbadge.classList.remove('has-count');return;}
    const {found}=lastPurify;
    const stats=lastPurify.stats || getPurifyStats(lastPurify.text,found,lastPurify.doc);
    const hasReady = !!(purifyCleanText && lastPurifyMap);
    const guardPending = !!(lastApplyGuardFailure && !hasReady);
    const roundText = purifyRoundInfo?.round ? `第${purifyRoundInfo.round}轮` : '';
    const statusText = purifyBusy && !hasReady
      ? `${roundText ? roundText + ' ' : ''}AI净化${cfg.purifyQaEnabled?' / 独立质检':''}进行中…`
      : hasReady
        ? `${roundText ? roundText + ' ' : ''}AI净化完成，等待应用到正文`
        : guardPending
          ? '上次写回被保险丝拦截，失败结果已丢弃；请点“返回重改”重新生成'
          : (cfg.autoFixEnabled ? '已检测到命中项；首轮会自动请求、校验并写回，手动按钮仅作失败兜底' : '已检测到命中项');
    area.style.display='';
    if(empty) empty.style.display='none';
    area.className='cc-purify-wrap';
    area.innerHTML=`
      <div class="cc-sec-hd" style="padding-top:9px;">
        <span class="cc-sec-lbl">🔍 净化检测 · ${stats.occurrenceCount}处 / ${stats.actionCount}个改写单元 / ${stats.ruleCount}类</span>
        <span class="cc-sec-act" id="cc-purify-clr">清除</span>
      </div>
      <div class="cc-ptags">${found.map(f=>`<span class="cc-ptag">${esc(f)}</span>`).join('')}</div>
      ${quotePairingBroken(lastPurify.text)?`<div style="font-size:10.5px;color:#c0392b;background:rgba(192,57,43,.08);border:1px solid rgba(192,57,43,.25);border-radius:8px;margin:4px 14px 6px;padding:6px 9px;line-height:1.5;">⚠️ 符号体检：本楼引号/星号配对不完整（开闭不匹配）。这是写作模型生成时丢的引号或历史楼层损坏残留——建议手动补好，否则模型会模仿坏符号，新楼越生成越乱。净化不会自动增删引号。${quoteIssueSnippets(lastPurify.text).map(sn=>`<br>· 疑似位置：${esc(sn)}`).join('')}</div>`:''}
      <div style="font-size:10px;color:var(--txt3);line-height:1.55;padding:0 14px 5px;">提示：自动模式会按设置连续写回最多 ${Math.max(1,Math.min(6,parseInt(cfg.autoFixMaxRounds,10)||1))} 轮；达到上限即停止，不会强迫打开面板。${cfg.purifyQaEnabled?'独立质检已开启，命中的质检范围会先审核/返修再写回。':'独立质检未开启，候选只经过客户端保险丝。'}</div>
      <div style="font-size:10.5px;color:${hasReady?'#a56a1c':'var(--txt3)'};background:${hasReady?'rgba(205,156,76,.10)':'rgba(0,0,0,.025)'};border:1px solid var(--bdr);border-radius:8px;margin:2px 14px 7px;padding:6px 9px;line-height:1.45;">${esc(statusText)}</div>
      ${lastApplyGuardFailure?`<div style="font-size:10.5px;color:#b4442f;background:rgba(192,57,43,.08);border:1px solid rgba(192,57,43,.22);border-radius:8px;margin:2px 14px 7px;padding:6px 9px;line-height:1.45;">🛡️ 上次写回被符号/重复保险丝拦截 ${lastApplyGuardFailure.blocked||1} 处，原文未动；失败结果已丢弃，不会再显示“应用到正文”。请点“返回重改”，让 AI 带更强禁令重新生成。</div>`:''}
      ${purifyCleanText?`<div class="cc-pclean" id="cc-pclean-view"><b style="font-size:10px;color:var(--txt3)">净化结果：</b><br>${esc(purifyCleanText).replace(/\n/g,'<br>')}</div>`:''}
      <div class="cc-pbtns">
        ${(!hasReady && !purifyBusy)?'<button type="button" class="cc-pb-ai" id="cc-purify-ai-btn">🤖 AI净化</button>':''}
        ${(lastApplyGuardFailure && !purifyBusy)?'<button type="button" class="cc-pb-ai" id="cc-purify-retry-btn">↩ 返回重改</button>':''}
        ${(hasReady && !lastApplyGuardFailure)?'<button type="button" class="cc-pb-apply show" id="cc-purify-apply-btn">✓ 应用到正文</button>':''}
        <button type="button" id="cc-purify-orig-btn">查看原文</button>
      </div>
    `;
    if(cfg.autoFixEnabled){ $pbadge.classList.remove('has-count'); }
    else { $pbadge.textContent=stats.occurrenceCount; $pbadge.classList.add('has-count'); }
    DOC.getElementById('cc-purify-clr').onclick=()=>{
      if(purifyBusy){showBubble('净化进行中，请等完成后再清除');return;}
      clearPurifyState(true);
    };
    const aiBtn=DOC.getElementById('cc-purify-ai-btn');
    if(aiBtn) aiBtn.onclick=runAiPurify;
    const retryBtn=DOC.getElementById('cc-purify-retry-btn');
    if(retryBtn) retryBtn.onclick=retryPurifyAfterGuardBlock;
    const applyBtn=DOC.getElementById('cc-purify-apply-btn');
    if(applyBtn) applyBtn.onclick=async()=>{
      if(purifyBusy){showBubble('净化进行中…');return;}
      if(!lastPurifyMap){showBubble('还没有可应用的净化结果，请等 AI 净化完成');return;}
      const roundSnapshot = purifyRoundInfo ? {...purifyRoundInfo} : {idx:lastPurify?.idx, round:1};
      const idxSnapshot = lastPurify?.idx;
      const mesElSnapshot = lastPurify?.mesEl || getMesElByIndex(idxSnapshot);
      purifyBusy=true;
      applyBtn.disabled=true; applyBtn.textContent='写入中…';
      let ok=false;
      try{ ok = await applyToChat(lastPurifyMap); }
      finally{ purifyBusy=false; updatePurifyArea(); }
      if(ok === true && cfg.autoFixEnabled){
        const nextRound=(roundSnapshot?.round || 1)+1;
        const maxRounds=Math.max(1,Math.min(6,parseInt(cfg.autoFixMaxRounds,10)||1));
        if(nextRound<=maxRounds) ccSetTimeout(()=>autoRunPurify(nextRound,idxSnapshot,mesElSnapshot),180);
      }
    };
    DOC.getElementById('cc-purify-orig-btn').onclick=()=>{
      const pclean=DOC.getElementById('cc-pclean-view')||area.querySelector('.cc-pclean');
      if(!pclean){
        const d=DOC.createElement('div'); d.className='cc-pclean';
        d.innerHTML=`<b style="font-size:10px;color:var(--txt3)">原文（高亮标注）：</b><br>${hlForbidden(lastPurify.displayText || lastPurify.text,lastPurify.found)}`;
        area.insertBefore(d,area.querySelector('.cc-pbtns'));
      } else { pclean.innerHTML=`<b style="font-size:10px;color:var(--txt3)">原文（高亮标注）：</b><br>${hlForbidden(lastPurify.displayText || lastPurify.text,lastPurify.found)}`; }
    };
  }

  let lastPurifyMap = null; // 存储最近一次解析好的替换映射
  let purifyRoundInfo = null; // {idx, round}：当前自动/手动净化轮次
  let lastApplyGuardFailure = null; // 写回被符号保险丝拦截后，保留原 map，允许“返回重改”兜底

  function rescanPurifyTarget(idx, fallbackMesEl){
    const target = getTargetMessageByIndex(idx) || (fallbackMesEl ? getTargetMessageFromEl(fallbackMesEl) : null);
    const doc = target ? getPurifyDocumentFromRaw(target.raw) : null;
    const text = doc?.scanText || '';
    if(!target || !text.trim()) return {ok:false, reason:'no-context'};
    const found = scanForbidden(text);
    if(!found.length){
      lastPurify=null; lastPurifyMap=null; purifyCleanText=''; purifyRoundInfo=null; lastApplyGuardFailure=null;
      updatePurifyArea();
      try { $pbadge.classList.remove('has-count'); } catch(e) {}
      return {ok:true, clean:true, target, text, found};
    }
    const stats=getPurifyStats(text,found,doc);
    lastPurify={text,displayText:doc.displayText,doc,found,hitItems:stats.hits,stats,mesEl:target.mesEl || fallbackMesEl,idx:target.idx};
    lastPurifyMap=null; purifyRoundInfo=null; lastApplyGuardFailure=null;
    purifyCleanText='';
    updatePurifyArea();
    return {ok:true, clean:false, target, text, found};
  }

  async function callPurifyAiSymbolRetry(text, found, previousMap){
    found = normalizeActiveFound(found);
    const hitItems = buildPurifyHitItems(text, found);
    if(!hitItems.length) return null;
    const sys = getPurifySystemPrompt();
    const selectedModel = resolveAiModel(cfg.aiBaseUrl,cfg.aiModel);
    const isQwen = isQwenThinkingModel(selectedModel);
    const previousLines = Object.values(normalizePurifyMap(previousMap || {})).map((a, i) => [
      `${i+1}. 上一版已作废 hit_id: ${a.id}`,
      `source: ${JSON.stringify(a.from)}`,
      `禁止再次输出同样 to: ${JSON.stringify(a.to)}`
    ].join('\n')).join('\n\n');
    const itemLines = hitItems.map((item, i) => {
      const hitWords = (item.hitWords || []).filter(Boolean);
      const structural = isStructuralPurifyItem(item);
      return [
        `${i+1}. type: ${structural ? 'structural_rewrite' : 'local_edit'}`,
        `label: ${item.label}`,
        hitWords.length ? `hit_word: ${hitWords.join('、')}` : '',
        `hit_id: ${item.id}`,
        `source: ${JSON.stringify(item.key)}`,
        structural
          ? '必须用 {"mode":"rewrite","to":"..."}，删除结构八股；to 必须保留引号/括号/星号等成对符号，逗号句号等行文标点可为句意通顺必要调整，但必须用得正确。'
          : '必须用 {"mode":"local","edits":[{"from":"覆盖命中词的原文连续片段","to":"结合语境后的替换片段"}]}，from/to 不许包含标点。',
        `rule: ${item.instruction}`
      ].filter(Boolean).join('\n');
    }).join('\n\n');
    const guard = [
      '上一次改写被本地保险丝拦截或无效，上一版失败结果已经作废。',
      '不要照抄上一版 value；不要保留上一版整句重写方式。现在从原始 source 重新做“AI 定点改写”。',
      '词语/短语型：只返回 local edits，由客户端在原句上写回；你不要接管标点。',
      '结构句式型：才允许 rewrite；必须保留 source 里的引号、括号、星号、反引号等成对符号，逗号、句号、问号、冒号、省略号、破折号等行文标点可为通顺必要调整。',
      '如果某条 source 无法在保住成对符号且标点正确、句意通顺的前提下有效改写，就省略对应 hit_id。',
      '只输出 JSON 对象，不要解释。'
    ].join('\n');
    const userMsg = (isQwen ? '/no_think\n' : '') + guard + '\n\n【上一版失败结果，已作废；仅作为禁用参考，禁止照抄】\n' + (previousLines || '（无）') + '\n\n【请重新处理的 hit_id 与 source】\n' + itemLines;
    const messages = isQwen ? [{role:'user',content:sys + '\n\n' + userMsg}] : [{role:'system',content:sys},{role:'user',content:userMsg}];
    let result = await callAI(messages, null, null, null, null, {jsonMode:true,disableThinking:true,omitTokenLimit:true,relaxed:true,acceptReasoningJson:true});
    if(!result && /^empty_response/.test(lastAiError)){
      const compact = '只输出 JSON。上次被拦截，上一版结果已作废。词语型用 local edits 且不动标点；结构型用 rewrite，可为通顺必要调整行文标点，但成对符号不能动，做不到就省略：\n' + hitItems.map(x => x.id + ' // ' + JSON.stringify(x.key) + ' // ' + x.label + ' // ' + x.instruction).join('\n');
      result = await callAI(isQwen ? [{role:'user',content:'/no_think\n' + compact}] : [{role:'system',content:sys},{role:'user',content:compact}], null, null, null, null, {disableThinking:true,omitTokenLimit:true,relaxed:true,acceptReasoningJson:true});
    }
    return result;
  }


  function dropSameAsFailedMap(map, failedMap){
    const normalized=normalizePurifyMap(map || {}), failed=normalizePurifyMap(failedMap || {}), out={};
    Object.entries(normalized).forEach(([id,a])=>{
      if(failed[id] && String(failed[id].to).trim()===String(a.to).trim()) return;
      out[id]=a;
    });
    return Object.keys(out).length?out:null;
  }

async function retryPurifyAfterGuardBlock(){
    if(!lastPurify?.found?.length){ showBubble('没有可返回重改的净化目标'); return false; }
    if(purifyBusy){ showBubble('净化进行中，请稍等…'); return false; }
    const failed = lastApplyGuardFailure || {map:lastPurifyMap, round:purifyRoundInfo?.round || 1, blocked:1, ts:Date.now()};
    const fresh = rescanPurifyTarget(lastPurify.idx,lastPurify.mesEl);
    if(!fresh.ok){ showBubble('无法重新读取当前正文，已停止返回重改'); return false; }
    if(fresh.clean){ showBubble('✓ 当前正文已经没有启用中的命中项'); return true; }
    // 返回重改必须基于当前正文重新生成命中 ID，不能沿用已经失效的旧坐标。
    lastApplyGuardFailure = null;
    lastPurifyMap = null;
    purifyCleanText = '';
    purifyBusy = true;
    updatePurifyArea();
    showBubble('↩ 已丢弃上一版被拦截结果，并退回 AI 定点重改：词语型只给局部 edits；结构型可为通顺必要调整行文标点，但成对符号仍锁死。', 12000);
    try{
      const sourceText = lastPurify.text;
      const sourceFound = lastPurify.found;
      const mapJson = await callPurifyAiSymbolRetry(sourceText, sourceFound, failed.map || {});
      const parsed = mapJson ? parseWordMap(mapJson) : null;
      let map = parsed ? filterPurifyMap(parsed, sourceText, sourceFound) : null;
      map = map ? dropSameAsFailedMap(map, failed.map || {}) : null;
      if(map){
        const qa=await maybeReviewPurifyMap(map,'返回重改结果');
        map=qa.map;
      }
      if(map){
        setPendingPurifyMap(map, failed.round || purifyRoundInfo?.round || 1);
        showBubble('✓ 已返回重改完成，旧结果已丢弃；现在是新结果，点“应用到正文”即可。', 10000);
        return true;
      }
      lastApplyGuardFailure = Object.assign({}, failed, {ts:Date.now()});
      lastPurifyMap = null;
      purifyCleanText = '';
      showBubble(parsed ? '⚠️ 返回重改后仍没有通过符号/有效性校验，旧结果已丢弃；可再点一次“返回重改”或查看原文手改。' : ('⚠️ 返回重改失败，旧结果已丢弃：' + (lastAiError || '模型未返回 JSON')), 10000);
      return false;
    } finally {
      purifyBusy = false;
      updatePurifyArea();
    }
  }

  async function requestPurifyMapForCurrent(){
    let map = null, usedFallback = false, parseFailed = false, invalidMap = false;
    if(cfg.purifyAiEnabled !== false && cfg.openaiKey){
      const mapJson = await callPurifyAi(lastPurify.text, lastPurify.found);
      if(mapJson){
        const parsed = parseWordMap(mapJson);
        parseFailed = !parsed;
        if(parsed){
          map = filterPurifyMap(parsed, lastPurify.text, lastPurify.found);
          invalidMap = !map;
        }
      }
    }
    if(!map){
      map = buildLocalPurifyFallback(lastPurify.text, lastPurify.found);
      usedFallback = !!map;
    }
    return {map, usedFallback, parseFailed, invalidMap};
  }

  function showPurifyFailure(result, prefix){
    prefix = prefix || '';
    if(result?.parseFailed) showBubble(prefix + '净化结果解析失败' + (lastAiError ? '：'+lastAiError : '，模型返回了非JSON内容'), 9000);
    else if(result?.invalidMap) showBubble(prefix + 'AI 返回了 JSON，但没有有效改写；可能是原样返回或改动过大，已丢弃', 9000);
    else if(!cfg.openaiKey) showBubble(prefix + '请先在「⚙️ 设置」填写 API Key；没有 AI 时不会本地机械直替', 9000);
    else showBubble(prefix + '净化请求失败：' + (lastAiError || '检查 API Key / URL / 模型'), 9000);
  }

  function setPendingPurifyMap(map, round){
    lastPurifyMap = map;
    purifyCleanText = actionPreviewDisplay(map);
    purifyRoundInfo = {idx:lastPurify.idx, round:round || 1};
    lastApplyGuardFailure = null;
    updatePurifyArea();
  }

  async function runAiPurify(){
    if(!lastPurify?.found?.length){showBubble('暂无检测数据');return;}
    if(purifyBusy){showBubble('净化进行中，请稍等…');return;}
    const fresh = rescanPurifyTarget(lastPurify.idx, lastPurify.mesEl);
    if(fresh.ok && fresh.clean){ showBubble('✓ 当前 context 已无启用中的净化项'); return; }
    if(!lastPurify?.found?.length){ showBubble('暂无启用中的检测数据'); return; }
    purifyBusy = true;
    purifyRoundInfo = {idx:lastPurify.idx, round:1};
    updatePurifyArea();
    showBubble('🔧 后台净化中；结果会保留在「清洗」页，未写入前不会提示已注入。', 15000);
    try {
      const result = await requestPurifyMapForCurrent();
      if(result.map){
        const qa=await maybeReviewPurifyMap(result.map,'手动净化结果');
        result.map=qa.map;
      }
      if(result.map){
        setPendingPurifyMap(result.map, 1);
        showBubble('✓ AI净化'+(cfg.purifyQaEnabled?'与独立质检':'')+'完成，待你确认应用到正文');
      } else showPurifyFailure(result, '');
    } finally {
      purifyBusy = false;
      updatePurifyArea();
    }
  }

  async function autoRunPurify(startRound=1, forcedIdx=null, forcedMesEl=null){
    if(purifyBusy) return;
    const initialIdx=Number.isInteger(forcedIdx)?forcedIdx:lastPurify?.idx;
    const initialMesEl=forcedMesEl || lastPurify?.mesEl || getMesElByIndex(initialIdx);
    if(!Number.isInteger(initialIdx) || initialIdx<0) return;
    const maxRounds=Math.max(1,Math.min(6,parseInt(cfg.autoFixMaxRounds,10)||1));
    let round=Math.max(1,parseInt(startRound,10)||1);
    if(round>maxRounds) return;
    purifySilentMode=true;
    hideBubble();
    try{$pbadge.classList.remove('has-count');}catch(e){}
    purifyBusy=true;
    let totalApplied=0,totalRejected=0,totalQaReviewed=0,totalQaRevised=0,totalQaRejected=0;
    let stopReason='';
    try{
      for(;round<=maxRounds;round++){
        const fresh=rescanPurifyTarget(initialIdx,initialMesEl);
        if(!fresh.ok){stopReason='无法重新读取当前 <context>';break;}
        if(fresh.clean){stopReason='clean';break;}
        lastPurify.found=normalizeActiveFound(lastPurify.found || []);
        if(!lastPurify.found.length){stopReason='clean';break;}
        purifyRoundInfo={idx:initialIdx,round};
        updatePurifyArea();
        const hitCount=lastPurify.stats?.occurrenceCount || lastPurify.hitItems?.length || 0;
        showBubble('🔁 自动清洗第 '+round+'/'+maxRounds+' 轮：检测到 '+hitCount+' 处，正在后台处理；正文不会整楼刷新。',12000);
        const result=await requestPurifyMapForCurrent();
        if(!result.map){
          showPurifyFailure(result,'⚠️ 第'+round+'轮自动净化：');
          stopReason='main-model-failed';
          break;
        }
        let map=result.map;
        if(cfg.purifyQaEnabled){
          const qa=await maybeReviewPurifyMap(map,'第'+round+'轮候选');
          totalQaReviewed+=qa.reviewed || 0;
          totalQaRevised+=qa.revised || 0;
          totalQaRejected+=qa.rejected || 0;
          map=qa.map;
          if(!map){
            stopReason=qa.failed?'qa-failed':'qa-rejected-all';
            break;
          }
        }
        lastPurifyMap=map;
        purifyCleanText=actionPreviewDisplay(map);
        updatePurifyArea();
        symbolGuardBlocked=0;
        const detail=await applyToChat(map,{quiet:true,returnDetails:true});
        if(!detail?.ok){
          totalRejected+=(detail?.rejected || []).length;
          stopReason=detail?.reason || 'write-failed';
          break;
        }
        totalApplied+=(detail.applied || []).length;
        totalRejected+=(detail.rejected || []).length;
      }
      const finalScan=rescanPurifyTarget(initialIdx,initialMesEl);
      if(finalScan.ok && finalScan.clean){
        const qaText=cfg.purifyQaEnabled?'；质检 '+totalQaReviewed+' 条，返修 '+totalQaRevised+' 条，拒绝 '+totalQaRejected+' 条':'';
        showBubble('✓ 自动清洗完成：静默写入 '+totalApplied+' 条，运行 '+Math.min(round,maxRounds)+' 轮'+qaText,9000);
        return true;
      }
      if(finalScan.ok && !finalScan.clean){
        const remain=lastPurify?.stats?.occurrenceCount || lastPurify?.hitItems?.length || 0;
        const reason=round>maxRounds?'已达到玩家设置的 '+maxRounds+' 轮上限':
          stopReason==='qa-rejected-all'?'本轮候选全部未通过独立质检':
          stopReason==='qa-failed'?'独立质检调用失败':
          stopReason || '本轮停止';
        showBubble('自动清洗已停止：'+reason+'。已写入 '+totalApplied+' 条，仍剩 '+remain+' 处；原文保留，可在面板手动处理。',10000);
      }else if(stopReason && stopReason!=='clean'){
        showBubble('自动清洗已停止：'+stopReason+'。已成功写入 '+totalApplied+' 条。',9000);
      }
      return false;
    }finally{
      purifyBusy=false;
      purifySilentMode=false;
      updatePurifyArea();
    }
  }

