    return playlist.map((p,i)=>({p,i})).filter(x => activeMusicCategory==='收藏' ? isFavorite(x.p) : (x.p.category || '日常') === activeMusicCategory).map(x => x.i);
  }
  function renderMusic(){
    if(!musicBuilt)return;
    const t=playlist[curTrack]||{};
    const mt=DOC.getElementById('cc-mtitle'),ma=DOC.getElementById('cc-mart'),mp=DOC.getElementById('cc-play');
    if(mt)mt.textContent=t.title||'—'; if(ma)ma.textContent=(t.artist||'') + (t.category ? ' · ' + t.category : '');
    if(mp)mp.innerHTML=isPlaying?icoPause():icoPlay();
    const nf=DOC.getElementById('cc-now-fav'); if(nf){const on=isFavorite(t);nf.textContent=on?'♥':'♡';nf.classList.toggle('on',on);}
    const dj=DOC.getElementById('cc-dj'); if(dj)dj.classList.toggle('playing',isPlaying);
    const cats=DOC.getElementById('cc-mcats');
    if(cats){
      cats.innerHTML=MUSIC_CATEGORIES.map(cat=>`<button class="cc-mcat ${cat===activeMusicCategory?'active':''}" data-cat="${esc(cat)}">${esc(cat)}</button>`).join('');
      cats.querySelectorAll('.cc-mcat').forEach(btn=>btn.onclick=()=>{activeMusicCategory=btn.dataset.cat; const ids=visibleTrackIndexes(); if(ids.length&&!ids.includes(curTrack)) switchTrack(ids[0]); else renderMusic();});
    }
    const ids=visibleTrackIndexes();
    const ml=DOC.getElementById('cc-mlist');
    if(ml)ml.innerHTML=ids.length ? ids.map((i,n)=>{const p=playlist[i],fav=isFavorite(p);return `<div class="cc-mitem ${i===curTrack?'active':''}" data-i="${i}"><span class="cc-mnum">${n+1}</span><span class="cc-mit-t">${esc(p.title)}</span>${i===curTrack&&isPlaying?'<span style="font-size:11px">♪</span>':''}<button class="cc-fav-btn ${fav?'on':''}" data-fav="${i}" title="${fav?'取消收藏':'收藏'}">${fav?'♥':'♡'}</button></div>`;}).join('') : `<div class="cc-no-entry">${activeMusicCategory==='收藏'?'还没有收藏歌曲':'这个分区还没有歌'}</div>`;
    if(ml){
      ml.querySelectorAll('.cc-mitem').forEach(el=>el.onclick=()=>switchTrack(parseInt(el.dataset.i)));
      ml.querySelectorAll('[data-fav]').forEach(btn=>btn.onclick=e=>{e.stopPropagation();toggleFavoriteTrack(parseInt(btn.dataset.fav));});
    }
  }
  function switchTrack(i){if(!playlist.length)return;curTrack=(i+playlist.length)%playlist.length;const t=playlist[curTrack];if(activeMusicCategory!=='收藏')activeMusicCategory=t.category||activeMusicCategory;stopDemo();if(t.demo){audio.removeAttribute('src');audio.load();}else if(audio.src!==t.url){audio.src=t.url;audio.load();}if(isPlaying)play();else renderMusic();}
  function switchVisible(delta){const ids=visibleTrackIndexes();if(!ids.length)return;const pos=Math.max(0,ids.indexOf(curTrack));switchTrack(ids[(pos+delta+ids.length)%ids.length]);}
  function togglePlay(){isPlaying?pause():play();}
  function play(){isPlaying=true;if(playlist[curTrack]?.demo)startDemo();else audio.play().catch(()=>showBubble('浏览器拦截了自动播放，请再点一次播放'));startNotes();renderMusic();}
  function pause(){isPlaying=false;audio.pause();stopDemo();stopNotes();renderMusic();}
  addCleanupListener(audio,'timeupdate',()=>{if(playlist[curTrack]?.demo)return;const cc=DOC.getElementById('cc-cur'),cd=DOC.getElementById('cc-dur'),cf=DOC.getElementById('cc-fill');if(cc)cc.textContent=fmt(audio.currentTime);if(cd)cd.textContent=fmt(audio.duration);if(cf)cf.style.width=(audio.duration?audio.currentTime/audio.duration*100:0)+'%';});
  addCleanupListener(audio,'ended',()=>switchVisible(1));
  function addFromText(){const ta=DOC.getElementById('cc-murl');ta.value.split('\n').map(s=>s.trim()).filter(Boolean).forEach(line=>{let title,url;if(line.includes('|')){const p=line.split('|');title=p[0].trim();url=p.slice(1).join('|').trim();}else{url=line;title=decodeURIComponent(url.split('/').pop().split('?')[0])||'未命名';}if(url)playlist.push({title,artist:'我的歌单',category:activeMusicCategory,url});});ta.value='';renderMusic();}
  function addFromFiles(e){[...e.target.files].forEach(f=>playlist.push({title:f.name.replace(/\.[^.]+$/,''),artist:'本地文件',category:activeMusicCategory,url:URL.createObjectURL(f)}));e.target.value='';renderMusic();}

  // ── 联网搜歌（GD Studio 聚合音乐 API，免key、支持CORS）──────
  const MUSIC_API = 'https://music-api.gdstudio.xyz/api.php';
  let musicSearchBusy = false;
  function fmtArtist(a){ return Array.isArray(a) ? a.join('/') : String(a||''); }
  async function searchOnlineMusic(){
    if(musicSearchBusy) return;
    const inp = DOC.getElementById('cc-msq');
    const box = DOC.getElementById('cc-msresult');
    const kw = (inp?.value||'').trim();
    if(!kw){ showBubble('先输入歌名或歌手再搜'); return; }
    musicSearchBusy = true;
    const srcSel = DOC.getElementById('cc-mssrc')?.value || 'netease';
    if(box) box.innerHTML = '<div class="cc-no-entry">搜索中…</div>';
    try{
      const r = await fetch(MUSIC_API + '?types=search&source=' + srcSel + '&name=' + encodeURIComponent(kw) + '&count=12&pages=1');
      if(!r.ok) throw new Error('HTTP ' + r.status);
      const list = await r.json();
      if(!Array.isArray(list) || !list.length){
        if(box) box.innerHTML = '<div class="cc-no-entry">没搜到「' + esc(kw) + '」，换个词或换个音源试试</div>';
        return;
      }
      if(box){
        box.innerHTML = list.map((s,i)=>{
          const t = esc(s.name||'未知'), a = esc(fmtArtist(s.artist));
          return '<div class="cc-mitem cc-msitem" data-id="' + esc(String(s.id)) + '" data-src="' + esc(s.source||srcSel) + '" data-t="' + t + '" data-a="' + a + '"><span class="cc-mnum">' + (i+1) + '</span><span class="cc-mit-t">' + t + ' · ' + a + '</span><span style="font-size:11px;opacity:.6">▶</span></div>';
        }).join('');
        box.querySelectorAll('.cc-msitem').forEach(el=>el.onclick=()=>playOnlineTrack(el.dataset.id, el.dataset.src, el.dataset.t, el.dataset.a));
      }
    }catch(e){
      if(box) box.innerHTML = '<div class="cc-no-entry">搜索失败：' + esc(e.message||'网络/跨域错误') + '；该免费接口偶尔抽风，稍后再试</div>';
    } finally { musicSearchBusy = false; }
  }
  async function playOnlineTrack(id, source, title, artist){
    try{
      showBubble('🎵 正在获取播放链接…');
      const r = await fetch(MUSIC_API + '?types=url&source=' + source + '&id=' + encodeURIComponent(id) + '&br=320');
      if(!r.ok) throw new Error('HTTP ' + r.status);
      const d = await r.json();
      let url = d?.url;
      if(!url){ showBubble('这首拿不到直链（多半是VIP/版权曲），换一首或换个音源'); return; }
      if(url.startsWith('http:')) url = 'https:' + url.slice(5); // 避免混合内容被浏览器拦截
      let idx = playlist.findIndex(p=>p.url===url);
      if(idx<0){ playlist.push({title:title||'未知', artist:(artist||'在线')+' · 在线', category:activeMusicCategory, url}); idx = playlist.length-1; }
      switchTrack(idx);
      if(!isPlaying) play();
      showBubble('✓ 已加入「' + activeMusicCategory + '」分区并开始播放');
    }catch(e){ showBubble('获取直链失败：' + (e.message||'网络错误')); }
  }
  function startNotes(){stopNotes();const host=DOC.getElementById('cc-tab-music')||$drawer;const stage=host.querySelector('.cc-mstage');if(!stage)return;const ns=['♪','♫','♩','♬'];noteTimer=ccSetInterval(()=>{if(ccCleaned||!stage.isConnected)return;const n=DOC.createElement('span');n.className='cc-note';n.textContent=pick(ns);const sv=Math.random()<.5?-1:1;n.style.left=(50+sv*(18+Math.random()*18))+'%';n.style.top='46%';n.style.setProperty('--dx',(sv*(10+Math.random()*20))+'px');n.style.setProperty('--rot',(sv*(10+Math.random()*20))+'deg');n.style.fontSize=(13+Math.random()*7)+'px';stage.appendChild(n);void n.offsetWidth;n.classList.add('go');ccSetTimeout(()=>n.remove(),1600);},460);}
  function stopNotes(){if(noteTimer!=null){ROOT.clearInterval(noteTimer);for(const t of ccTimers){if(t.type==='interval'&&t.id===noteTimer){ccTimers.delete(t);break;}}}noteTimer=null;}
  function startDemo(){stopDemo();try{const AC=ROOT.AudioContext||ROOT.webkitAudioContext;const ctx=new AC();const tempo=0.46;let step=0;const bass=[55,0,82.4,0,65.4,0,82.4,98],blip=[0,880,0,0,0,660,0,0];const tick=()=>{if(ccCleaned)return;const nw=ctx.currentTime,f=bass[step%8],b=blip[step%8];if(f)playTone(ctx,f,nw,0.22,'sine',0.18);if(b)playTone(ctx,b,nw,0.08,'square',0.05);step++;const cur=step*tempo;const cc=DOC.getElementById('cc-cur'),cd=DOC.getElementById('cc-dur'),cf=DOC.getElementById('cc-fill');if(cc)cc.textContent=fmt(cur);if(cd)cd.textContent='∞';if(cf)cf.style.width=(50+50*Math.sin(step/3))+'%';};tick();demoBeat={ctx,iv:ccSetInterval(tick,tempo*1000)};}catch(e){}}
  function playTone(ctx,freq,t,dur,type,gain){const o=ctx.createOscillator(),g=ctx.createGain();o.type=type;o.frequency.value=freq;g.gain.setValueAtTime(0,t);g.gain.linearRampToValueAtTime(gain,t+0.01);g.gain.exponentialRampToValueAtTime(0.0001,t+dur);o.connect(g);g.connect(ctx.destination);o.start(t);o.stop(t+dur+0.02);}
  function stopDemo(){if(demoBeat){if(demoBeat.iv!=null){ROOT.clearInterval(demoBeat.iv);for(const t of ccTimers){if(t.type==='interval'&&t.id===demoBeat.iv){ccTimers.delete(t);break;}}}try{demoBeat.ctx.close();}catch(e){}demoBeat=null;}}

  // ── 设置 Tab ────────────────────────────────────────────────
  function buildPurifyRuleTab(){
    const pane=DOC.getElementById('cc-tab-purifyrule'); if(!pane)return;
    const wordChip = (word, type) => {
      const disabled = isBuiltinWordDisabled(word);
      const label = type === 'anatomy' ? '医学/专业词' : '八股词';
      return `<button type="button" class="cc-ptag cc-word-chip" data-bwtoggle="${esc(word)}" title="${disabled?'点击启用':'点击停用'} · ${esc(label)}" style="border:none;cursor:pointer;${disabled?'opacity:.45;text-decoration:line-through;':''}">${esc(word)}</button>`;
    };
    const wordChips = FORB_WORDS.map(w => wordChip(w,'word')).join('');
    const anatomyChips = FORB_ANATOMY.map(w => wordChip(w,'anatomy')).join('');
    const activeWordCount = FORB_WORDS.filter(w => !isBuiltinWordDisabled(w)).length;
    const activeAnatomyCount = FORB_ANATOMY.filter(w => !isBuiltinWordDisabled(w)).length;

    const builtinPatterns = Object.keys(PATTERN_INSTRUCTIONS).map(label => {
      const disabled = isBuiltinPatternDisabled(label);
      return `
      <div class="cc-rule-card" data-bpcard="${esc(label)}" style="${disabled?'opacity:.58;':''}">
        <div class="cc-rule-title">
          <span>句式 · ${esc(label)}${disabled?'（已停用）':''}</span>
          <span><button class="cc-mini-btn" data-bpedit="${esc(label)}">保存</button><button class="cc-mini-btn" data-bpreset="${esc(label)}">还原</button><button class="cc-mini-btn ${disabled?'':'danger'}" data-bptoggle="${esc(label)}">${disabled?'启用':'停用'}</button></span>
        </div>
        <textarea class="cc-rule-textarea" data-bpinst="${esc(label)}">${esc(getPatternInstruction(label))}</textarea>
      </div>`;
    }).join('');

    const customWords = customPurifyWords.length ? customPurifyWords.map((item, idx) => `
      <div class="cc-rule-card">
        <div class="cc-rule-title"><span>${item.type==='anatomy'?'医学/专业词':'八股词'} · ${esc(item.word)}</span><span><button class="cc-mini-btn" data-cwtest="${idx}">测试本轮</button><button class="cc-mini-btn danger" data-cwdel="${idx}">删除</button></span></div>
        <div style="font-size:10px;color:var(--txt3);line-height:1.5;">${hasCustomWordWildcard(item.word)?'通配词：会解析为正文里实际出现的词，例如 x骨 → 腕骨/颧骨。':''}</div>
      </div>`).join('') : '<div class="cc-no-entry">暂无自定义词条</div>';

    const customPatterns = customPurifyPatterns.length ? customPurifyPatterns.map((item, idx) => `
      <div class="cc-rule-card">
        <div class="cc-rule-title"><span>句式 · ${esc(item.label)}</span><button class="cc-mini-btn danger" data-cpdel="${idx}">删除</button></div>
        <div style="font-size:10px;color:var(--txt3);margin-bottom:4px;">/${esc(item.pattern)}/${esc(item.flags || '')}</div>
        <div>${esc(item.instruction || '')}</div>
      </div>`).join('') : '<div class="cc-no-entry">暂无自定义句式</div>';

    pane.innerHTML=`
      <div class="cc-rule-card">
        <div class="cc-rule-title"><span>AI 总提示词</span><span><button class="cc-mini-btn" id="ss-sys-save">保存</button><button class="cc-mini-btn" id="ss-sys-reset">还原默认</button></span></div>
        <textarea class="cc-rule-textarea" id="ss-sys-prompt" style="min-height:145px;">${esc(getPurifySystemPrompt())}</textarea>
      </div>

      <div class="cc-rule-card">
        <div class="cc-rule-title"><span>分类修改规则</span><span><button class="cc-mini-btn" id="ss-cat-save">保存</button><button class="cc-mini-btn" id="ss-cat-reset">还原默认</button></span></div>
        <div class="cc-slabel" style="padding:0;margin:0 0 4px;">八股词这一类怎么改</div>
        <textarea class="cc-rule-textarea" id="ss-word-rule" style="min-height:84px;">${esc(getCategoryRule('word'))}</textarea>
        <div class="cc-slabel" style="padding:8px 0 0;margin:0 0 4px;">医学/解剖/专业词这一类怎么改</div>
        <textarea class="cc-rule-textarea" id="ss-anatomy-rule" style="min-height:84px;">${esc(getCategoryRule('anatomy'))}</textarea>
      </div>

      <div class="cc-rule-card">
        <div class="cc-rule-title"><span>内置八股词库</span><span>${activeWordCount}/${FORB_WORDS.length}启用</span></div>
        <div style="font-size:10px;color:var(--txt3);margin-bottom:6px;">点词条即可停用/启用。比如能接受“锁骨”，就在下面医学词库里点掉它。</div>
        <div class="cc-ptags" style="padding:2px 0 0;">${wordChips || '<span style="font-size:11px;color:var(--txt3);">无内置词</span>'}</div>
      </div>

      <div class="cc-rule-card">
        <div class="cc-rule-title"><span>内置医学/解剖/专业词库</span><span>${activeAnatomyCount}/${FORB_ANATOMY.length}启用</span></div>
        <div style="font-size:10px;color:var(--txt3);margin-bottom:6px;">点词条即可停用/启用；停用后不会再检测这个内置词。</div>
        <div class="cc-ptags" style="padding:2px 0 0;">${anatomyChips || '<span style="font-size:11px;color:var(--txt3);">无内置词</span>'}</div>
      </div>

      <div class="cc-divider"></div>
      <div class="cc-slabel">＋ 自定义词条</div>
      <div style="font-size:10px;color:var(--txt3);line-height:1.55;margin:2px 0 6px;">支持通配写法：x骨 / xx骨 / *椎。新增后会立即写入本地词库；若通配命中了已停用的内置词，该词会被保护，不会被通配复活。</div>
      <div id="ss-custom-words-list">${customWords}</div>
      <div class="cc-rule-grid">
        <input type="text" id="ss-cw-word" placeholder="要检测的词，例：x骨、xx椎、某种" style="flex:2;min-width:110px;">
        <select id="ss-cw-type" style="flex:1;min-width:112px;"><option value="word">八股词</option><option value="anatomy">医学/专业词</option></select>
        <button id="ss-cw-add">＋添加词条</button>
      </div>

      <div class="cc-divider"></div>
      <div class="cc-slabel">内置句子模式/提示词</div>
      ${builtinPatterns}

      <div class="cc-divider"></div>
      <div class="cc-slabel">＋ 自定义句子模式</div>
      <div id="ss-custom-patterns-list">${customPatterns}</div>
      <div class="cc-rule-grid">
        <input type="text" id="ss-cp-label" placeholder="模式名，如：定义句" style="flex:1;min-width:110px;">
        <input type="text" id="ss-cp-pattern" placeholder="正则，如：[^。！？]{0,30}是[^。！？]{0,20}的" style="flex:2;min-width:180px;">
        <input type="text" id="ss-cp-flags" placeholder="flags 可空，如 i" style="width:80px;">
        <textarea id="ss-cp-inst" placeholder="告诉 AI 这种句子应该怎么改，例如：不要用定义句，改成主观体验或肯定描写；不要扩写。"></textarea>
