      categoryPurifyRules.anatomy = DOC.getElementById('ss-anatomy-rule').value.trim();
      saveCategoryPurifyRules();
      markPurifyRulesChanged();
      showBubble('✓ 已保存分类修改规则，已重新扫描本轮 context');
    };
    DOC.getElementById('ss-cat-reset').onclick=()=>{
      categoryPurifyRules = {};
      saveCategoryPurifyRules();
      markPurifyRulesChanged();
      buildPurifyRuleTab();
      showBubble('已还原分类默认规则，已重新扫描本轮 context');
    };
    DOC.getElementById('ss-sys-save').onclick=()=>{ purifySystemPrompt=DOC.getElementById('ss-sys-prompt').value.trim(); savePurifySystemPrompt(); showBubble('✓ 已保存 AI 总提示词'); };
    DOC.getElementById('ss-sys-reset').onclick=()=>{ purifySystemPrompt=''; savePurifySystemPrompt(); buildPurifyRuleTab(); showBubble('已还原默认 AI 总提示词'); };

    pane.querySelectorAll('[data-bwtoggle]').forEach(btn=>{
      btn.onclick=()=>{ const word=btn.dataset.bwtoggle; setBuiltinWordDisabled(word, !isBuiltinWordDisabled(word)); buildPurifyRuleTab(); showBubble('✓ 已'+(isBuiltinWordDisabled(word)?'停用':'启用')+'：'+word); };
    });
    pane.querySelectorAll('[data-bpedit]').forEach(btn=>{
      btn.onclick=()=>{ const label=btn.dataset.bpedit; const ta=[...pane.querySelectorAll('[data-bpinst]')].find(x => x.dataset.bpinst === label); const inst=ta?.value.trim(); if(!inst){showBubble('规则不能为空');return;} builtinPatternInstructions[label]=inst; saveBuiltinPatternInstructions(); markPurifyRulesChanged(); buildPurifyRuleTab(); showBubble('✓ 已保存句式规则：'+label+'，已重新扫描本轮 context'); };
