    });
    pane.querySelectorAll('[data-bptoggle]').forEach(btn=>{
      btn.onclick=()=>{ const label=btn.dataset.bptoggle; setBuiltinPatternDisabled(label, !isBuiltinPatternDisabled(label)); buildPurifyRuleTab(); showBubble('✓ 已'+(isBuiltinPatternDisabled(label)?'停用':'启用')+'句式：'+label); };
    });
    pane.querySelectorAll('[data-cwtest]').forEach(btn=>{
      btn.onclick=()=>{
        const item = customPurifyWords[parseInt(btn.dataset.cwtest,10)];
        const target = getLatestAiTarget();
        const text = target ? getPurifyTextFromRaw(target.raw) : '';
        const hits = getCustomWordActualMatches(text, item);
        showBubble(hits.length ? ('✓ 本轮 context 命中：' + hits.join('、')) : '本轮 context 暂未命中这个自定义词条', 7000);
      };
    });
    pane.querySelectorAll('[data-cwdel]').forEach(btn=>{
      btn.onclick=()=>{ customPurifyWords.splice(parseInt(btn.dataset.cwdel,10),1); saveCustomWords(); markPurifyRulesChanged(); buildPurifyRuleTab(); showBubble('已删除词条，已重新扫描本轮 context'); };
    });
    pane.querySelectorAll('[data-cpdel]').forEach(btn=>{
      btn.onclick=()=>{ customPurifyPatterns.splice(parseInt(btn.dataset.cpdel,10),1); saveCustomPatterns(); markPurifyRulesChanged(); buildPurifyRuleTab(); showBubble('已删除句式，已重新扫描本轮 context'); };
    });
    DOC.getElementById('ss-cw-add').onclick=()=>{
      const word=DOC.getElementById('ss-cw-word').value.trim();
      const type=DOC.getElementById('ss-cw-type').value;
      if(!word){ showBubble('请填写要检测的词'); return; }
      if(customPurifyWords.some(i=>i.word===word)){ showBubble('该词已存在'); return; }
      const newItem = {word,type};
      customPurifyWords.push(newItem); saveCustomWords(); markPurifyRulesChanged(); buildPurifyRuleTab();
      const target = getLatestAiTarget();
      const text = target ? getPurifyTextFromRaw(target.raw) : '';
      const hits = getCustomWordActualMatches(text, newItem);
      showBubble('✓ 已添加词条：'+word + (hits.length ? '；本轮已命中：'+hits.join('、') : '；本轮暂未命中'), 7000);
    };
    DOC.getElementById('ss-cp-add').onclick=()=>{
      const label=DOC.getElementById('ss-cp-label').value.trim();
      const pattern=DOC.getElementById('ss-cp-pattern').value.trim();
      const flags=DOC.getElementById('ss-cp-flags').value.trim();
      const instruction=DOC.getElementById('ss-cp-inst').value.trim();
      if(!label||!pattern||!instruction){ showBubble('请填写模式名、正则和修改规则'); return; }
      if(!safeRegExp(pattern, flags)){ showBubble('正则无效，请检查'); return; }
      if(customPurifyPatterns.some(i=>i.label===label && i.pattern===pattern)){ showBubble('该句式已存在'); return; }
      customPurifyPatterns.push({label,pattern,flags,instruction}); saveCustomPatterns(); markPurifyRulesChanged(); buildPurifyRuleTab(); showBubble('✓ 已添加句式：'+label+'，已重新扫描本轮 context');
    };
  }


  function buildSettingsTab(){
    const pane=DOC.getElementById('cc-tab-settings'); if(!pane)return;
    if(pane.dataset.built)return;
