  // ─── 抽屉开关 ─────────────────────────────────────────────
  let drawerOpen=false;
  function openDrawer(){
    if(!drawerBuilt) buildDrawer();
    drawerOpen=true;
    $drawer.classList.add('is-open');
    $overlay.classList.add('is-visible');
    if(activeTab==='purify') refreshPurifyPane();
    autoScanLatestContext();
  }
  function closeDrawer(){
    drawerOpen=false;
    $drawer.classList.remove('is-open');
    $overlay.classList.remove('is-visible');
  }

  // ─── 永久入口救援（硬兜底）─────────────────────────────────
  // 两个普通入口都关闭时，必须留下一个实际可点击、不会超时消失的屏幕边缘把手。
  // /clawed 同时注册为 SillyTavern 原生斜杠命令；DOM 监听仅作为旧版/助手环境兜底。
  const CLAWED_RESCUE_COMMAND_RE = /^\/(?:clawed|cc)(?:\s+open)?$/i;
  let nativeSlashCommand = null;
  const rescueBoundInputs = new WeakSet();
  const rescueBoundSendButtons = new WeakSet();
  let rescueShortcutStamp = 0;

  function rescueNeeded(){
    return cfg.floatEnabled === false && cfg.extensionMenuEnabled === false;
  }
  function applyRescueVisibility(){
    if(ccCleaned) return;
    const show = rescueNeeded();
    $rescue.classList.toggle('is-visible', show);
    $rescue.style.display = show ? 'flex' : 'none';
  }
  function openClawedRescue(source){
    if(ccCleaned) return false;
    try { mountUI(); } catch(e) {}
    try { closeDrawer(); } catch(e) {}
    openDrawer();
    try { switchTab('settings'); } catch(e) {}
    try { $drawer.scrollTop = 0; } catch(e) {}
    try { console.info('[Clawed] rescued from:', source || 'unknown'); } catch(e) {}
    return true;
  }
  ROOT.__CLAWED_OPEN__ = openClawedRescue;
  addCleanupListener($rescue,'click',e=>{
    e.preventDefault(); e.stopPropagation();
    openClawedRescue('persistent-rescue-handle');
  },true);
  addCleanupListener($rescue,'keydown',e=>{
    if(e.key==='Enter'||e.key===' '){ e.preventDefault(); openClawedRescue('persistent-rescue-keyboard'); }
  });

  function getClawedCommandInput(){
    const candidates = [
      '#send_textarea', '#send_form textarea', '#rightSendForm textarea',
      'textarea[name="send_textarea"]', '#send_form [contenteditable="true"]',
      '#rightSendForm [contenteditable="true"]', '[contenteditable="true"][id*="send" i]'
    ];
    for(const sel of candidates){
      try { const el=DOC.querySelector(sel); if(el && el.isConnected) return el; } catch(e) {}
    }
    return null;
  }
  function readClawedCommandInput(el){
    if(!el) return '';
    return String(('value' in el ? el.value : el.textContent) || '').trim();
  }
  function clearClawedCommandInput(el){
    if(!el) return;
    try {
