  }, {passive:false,capture:true});

  addCleanupListener(DOC,'touchend',e=>{
    if(Date.now()-lastPointerAt<700) return;
    if(!drag) return;
    lastTouchAt=Date.now();
    e.preventDefault(); e.stopPropagation();
    endBtnDrag(true);
  }, {passive:false,capture:true});

  addCleanupListener(DOC,'touchcancel',e=>{
    if(Date.now()-lastPointerAt<700) return;
    if(!drag) return;
    const tapLike = !moved && Date.now()-downTime < 650;
    resetBtnDrag();
    if(tapLike) activateBtn();
  }, {passive:true,capture:true});

  // 最后一层保险：如果 pointer/touch 都没触发打开，但系统仍派发 click，就由 click 打开。
  addCleanupListener($btn,'click',e=>{
    const now=Date.now();
    if(now<suppressClickUntil){
      e.preventDefault(); e.stopPropagation();
      return;
    }
    // pointerup/touchend 丢失时，click 兜底打开。
    e.preventDefault(); e.stopPropagation();
    activateBtn();
  }, {capture:true});

  function isChatInput(el){
    if(!el) return false;
    return !!el.closest?.('#send_textarea, #send_form, #rightSendForm, .sendForm, [contenteditable="true"]');
  }
  addCleanupListener(DOC,'focusin',e=>{ if(isChatInput(e.target)) autoScanLatestContext(); },true);

  // ─── 闲置检测 ─────────────────────────────────────────────
  let lastAct=Date.now(),idlePoked=false;
  function markAct(){lastAct=Date.now();idlePoked=false;}
  ['mousemove','mousedown','keydown','touchstart'].forEach(ev=>addCleanupListener(DOC,ev,markAct,{passive:true}));
  ccSetInterval(()=>{
    if(!cfg.idle||idlePoked)return;
    if(Date.now()-lastAct>cfg.idleMins*60000){idlePoked=true;$btn.classList.add('cc-nudge');ccSetTimeout(()=>$btn.classList.remove('cc-nudge'),3300);showBubble(pick(IDLE_MSGS),7000);}
  },15000);

  // ─── 定时器 ───────────────────────────────────────────────
  ccSetInterval(async()=>{
    const mins=Math.round((Date.now()-startTime)/60000); if(mins<1||mins%cfg.interval!==0)return;
    const r=Math.random();
    if(r<.35&&cfg.rest)showBubble(msgRest(mins));
    else if(r<.6&&cfg.weather){const wx=await fetchWeather();showBubble(wx?msgWeather(wx):pick(RAND_MSGS));}
    else if(r<.82&&cfg.timeGreet)showBubble(timeGreetMsg());
    else showBubble(pick(RAND_MSGS));
  },60000);

  let aiElapsed=0;
  ccSetInterval(async()=>{
    if(!cfg.aiEnabled||!cfg.openaiKey)return;
    if(++aiElapsed<cfg.aiInterval)return;
    aiElapsed=0; const msg=await fetchAiMsg(); if(msg)showBubble(msg);
  },60000);

  ccSetTimeout(()=>{
    applyRescueVisibility();
    if(rescueNeeded()){
      showBubble('🛟 两个普通入口已关闭。右侧永久 🦀 把手可随时召回；也可以输入 /clawed。',8000);
    } else {
      showBubble(cfg.timeGreet?GREET[timeBucket(new Date().getHours())]:'— Clawed 在此 —');
    }
  },2500);
  // 尽早挂载，避免插件加载后的第一条短回复在 3 秒观察器空窗期内完成而漏掉。
  ccSetTimeout(()=>{if(cfg.purifyEnabled||cfg.autoFixEnabled)startPurifyObserver();},120);
  ccSetTimeout(()=>{if(cfg.purifyEnabled||cfg.autoFixEnabled)startPurifyObserver();},900);
  ccSetTimeout(()=>{if(cfg.purifyEnabled||cfg.autoFixEnabled)startPurifyObserver();},3000);


  // ─── 扩展程序菜单入口 ─────────────────────────────────────
  function removeExtensionMenuBtn(){
    const old=DOC.getElementById('cc-ext-menu-item');
    if(old) old.remove();
  }
  function getExtensionsMenuContainer(){
    const sels=[
      '#extensionsMenu .list-group','#extensionsMenu','#extensionsMenuList',
      '#extensionsMenuDrawer .list-group','#extensionsMenuDrawer',
      '#extensions_menu .list-group','#extensions_menu',
      '.extensionsMenu .list-group','.extensionsMenu',
      '[id*="extensions" i] .list-group','[id*="extension" i] .list-group'
    ];
    for(const sel of sels){ const el=DOC.querySelector(sel); if(el) return el; }
    return null;
  }
  function mountExtensionMenuBtn(){
    if(ccCleaned) return;
    if(cfg.extensionMenuEnabled===false){ removeExtensionMenuBtn(); return; }
    const existing=DOC.getElementById('cc-ext-menu-item');
    if(existing?.dataset?.ccOwner===ccOwnerToken) return;
    if(existing) existing.remove();
    const menu=getExtensionsMenuContainer();
    if(!menu) return;
    const item=DOC.createElement('div');
    item.id='cc-ext-menu-item';
    item.dataset.ccOwner=ccOwnerToken;
    item.className='list-group-item flex-container flexGap5 interactable';
    item.title='打开 Clawed';
    item.tabIndex=0;
    item.setAttribute('role','listitem');
    item.innerHTML='<div class="fa-fw extensionsMenuExtensionButton" style="font-size:15px;line-height:1">🦀</div><span>Clawed</span>';
    item.onclick=e=>{if(ccCleaned)return;e.preventDefault();e.stopPropagation();toggleDrawer();};
    item.onkeydown=e=>{if(ccCleaned)return;if(e.key==='Enter'||e.key===' '){e.preventDefault();toggleDrawer();}};
    menu.appendChild(item);
  }
  function applyExtensionMenuVisibility(){
    if(cfg.extensionMenuEnabled===false) removeExtensionMenuBtn();
    else mountExtensionMenuBtn();
  }
  function getNativeExtensionsMenuButtons(){
    const selectors=[
      '#extensionsMenuButton','#extensionsMenuBtn','[data-i18n="Extensions"]',
      '[title*="Extensions" i]','[title*="扩展" i]','.extensionsMenuButton'
    ];
    const out=[];
    selectors.forEach(sel=>{ try{ DOC.querySelectorAll(sel).forEach(el=>{ if(el && !out.includes(el)) out.push(el); }); }catch(e){} });
    return out;
  }
  function watchExtensionsMenuButton(){
    if(ccCleaned) return;
    getNativeExtensionsMenuButtons().forEach(btn=>{
      if(btn.dataset.ccClawedHook===ccOwnerToken)return;
      btn.dataset.ccClawedHook=ccOwnerToken;
      addCleanupListener(btn,'click',()=>ccSetTimeout(mountExtensionMenuBtn,120));
      // 双击会被第一次点击导致的菜单重绘打断，改为桌面右键和触屏长按。
      addCleanupListener(btn,'contextmenu',e=>{
        e.preventDefault(); e.stopPropagation();
        openClawedRescue('wand-context-menu');
      },true);
      let holdTimer=null, holdTriggered=false;
      const clearHold=()=>{ if(holdTimer!=null){ try{ROOT.clearTimeout(holdTimer);}catch(e){} holdTimer=null; } };
      addCleanupListener(btn,'pointerdown',e=>{
        if(e.pointerType==='mouse') return;
        clearHold(); holdTriggered=false;
        holdTimer=ROOT.setTimeout(()=>{ holdTimer=null; holdTriggered=true; openClawedRescue('wand-long-press'); },700);
      },{passive:true});
      ['pointerup','pointercancel','pointerleave'].forEach(type=>addCleanupListener(btn,type,clearHold,{passive:true}));
      addCleanupListener(btn,'click',e=>{
        if(!holdTriggered) return;
        holdTriggered=false; e.preventDefault(); e.stopPropagation();
      },true);
      addCleanupStop(clearHold);
    });
  }
  mountExtensionMenuBtn();
  watchExtensionsMenuButton();

  // ─── ST 按钮注册 ──────────────────────────────────────────
  const CLAWED_SCRIPT_BUTTON_NAMES = ['🦀 菜单','🦀 Clawed','Clawed 菜单','打开 Clawed'];
  const clawedButtonEventRev = Date.now() + ':' + Math.random();
  ROOT.__CLAWED_BUTTON_EVENT_REV__ = clawedButtonEventRev;
  const clawedBoundButtonNames = new Set();
  function openClawedFromScriptButton(){
    if(ccCleaned||ROOT.__CLAWED_BUTTON_EVENT_REV__ !== clawedButtonEventRev) return;
    openDrawer();
    ccSetTimeout(()=>{ if(!ccCleaned&&ROOT.__CLAWED_BUTTON_EVENT_REV__ === clawedButtonEventRev) openDrawer(); }, 80);
  }
  function getClawedButtonApi(){
    const ctx = (()=>{ try{return ROOT.SillyTavern?.getContext?.();}catch(e){return null;} })();
    const scopes = [window, ROOT, ctx].filter(Boolean);
    const getEvt = (typeof getButtonEvent === 'function' ? getButtonEvent : scopes.map(x=>x.getButtonEvent).find(fn=>typeof fn === 'function'));
    const onEvt = (typeof eventOn === 'function' ? eventOn : scopes.map(x=>x.eventOn).find(fn=>typeof fn === 'function'));
    return {getEvt, onEvt};
  }
  function registerClawedButtonEvents(){
    if(ccCleaned) return;
    try{
      if(typeof appendInexistentScriptButtons === 'function') appendInexistentScriptButtons([{name:'🦀 菜单', visible:true}]);
    }catch(e){}
    try{
      const {getEvt, onEvt} = getClawedButtonApi();
      if(typeof getEvt !== 'function' || typeof onEvt !== 'function') return;
      CLAWED_SCRIPT_BUTTON_NAMES.forEach(name=>{
        if(clawedBoundButtonNames.has(name)) return;
        try{
          const ev = getEvt(name);
          if(!ev) return;
          const ret = onEvt(ev, openClawedFromScriptButton);
          addCleanupStop(ret);
          clawedBoundButtonNames.add(name);
        }catch(e){}
      });
    }catch(e){}
  }
  registerClawedButtonEvents();
  [250, 800, 1600, 3000, 5000].forEach(ms=>ccSetTimeout(registerClawedButtonEvents, ms));
  // ─── DOM 变化监听 ─────────────────────────────────────────
  const ccDomObserver = new MutationObserver(()=>{
    if(ccCleaned)return;
    if(!$btn.isConnected || !$drawer.isConnected || !$rescue.isConnected)mountUI();
    applyRescueVisibility();
    bindRescueDomTargets();
    watchExtensionsMenuButton();
    mountExtensionMenuBtn();
    if(cfg.purifyEnabled || cfg.autoFixEnabled) startPurifyObserver();
  });
  ccDomObserver.observe(DOC.documentElement,{childList:true,subtree:true});
  ccObservers.push(ccDomObserver);

  const clawedCleanup = function(reason){
    if(ccCleaned) return;
    ccCleaned=true;
    try { stopDemo(); } catch(e) {}
    try { stopNotes(); } catch(e) {}
    try { clearBubbleTimer(); } catch(e) {}
    try { audio.pause(); audio.removeAttribute('src'); audio.load(); } catch(e) {}
    try { playlist.forEach(t=>{ if(String(t?.url||'').startsWith('blob:')) URL.revokeObjectURL(t.url); }); } catch(e) {}
    if(purifyEventBinding){
      try {
        const {es,bindings,event,handler}=purifyEventBinding;
        const list=Array.isArray(bindings)?bindings:(event&&handler?[{event,handler}]:[]);
        list.forEach(x=>{
          if(typeof es?.off==='function') es.off(x.event,x.handler);
          else if(typeof es?.removeListener==='function') es.removeListener(x.event,x.handler);
        });
      } catch(e) {}
      purifyEventBinding=null;
    }
    ccCleanupStops.splice(0).forEach(stop=>{ try { stop(); } catch(e) {} });
    for(const t of [...ccTimers]){ try { t.type === 'interval' ? ROOT.clearInterval(t.id) : ROOT.clearTimeout(t.id); } catch(e) {} }
    ccTimers.clear();
    ccObservers.splice(0).forEach(o => { try { o.disconnect(); } catch(e) {} });
    ccCleanupListeners.splice(0).forEach(x => { try { x.target.removeEventListener(x.type, x.fn, x.opts); } catch(e) {} });
    try {
      getNativeExtensionsMenuButtons().forEach(extBtn=>{
        if(extBtn?.dataset?.ccClawedHook===ccOwnerToken) delete extBtn.dataset.ccClawedHook;
      });
    } catch(e) {}
    ['cc-btn','cc-overlay','cc-drawer','cc-bubble','cc-rescue-handle','cc-ext-menu-item','cc-sb','cc-style'].forEach(id => {
      try {
        const el=DOC.getElementById(id);
        if(el && (!el.dataset?.ccOwner || el.dataset.ccOwner===ccOwnerToken)) el.remove();
      } catch(e) {}
    });
    if(ROOT.__CLAWED_BUTTON_EVENT_REV__===clawedButtonEventRev) ROOT.__CLAWED_BUTTON_EVENT_REV__='';
    if(ROOT.__CLAWED_OPEN__===openClawedRescue) delete ROOT.__CLAWED_OPEN__;
    if(ROOT.__CLAWED_OWNER__===ccOwnerToken){ ROOT.__CLAWED_INIT__=false; delete ROOT.__CLAWED_OWNER__; }
    if(ROOT.__CLAWED_CLEANUP__===clawedCleanup) delete ROOT.__CLAWED_CLEANUP__;
    try { console.info('[Clawed] cleaned:', reason||'unknown'); } catch(e) {}
  };
  ROOT.__CLAWED_CLEANUP__ = clawedCleanup;

  // ─── 预设生命周期绑定 ─────────────────────────────────────
  // 仅仅“从某个预设启动”并不代表 iframe 会随预设切换而销毁。
  // SillyTavern 官方会在切换预设/API 时发出 PRESET_CHANGED / MAIN_API_CHANGED，
  // 这里由旧实例主动 cleanup；新预设若同样包含 Clawed，会启动一个新的 owner 实例。
  let presetLifecycleArmed = false;
  let presetLifecycleBound = false;
  let presetLifecycleSignature = '';

  function readPresetManagerName(pm){
    if(!pm) return '';
    const methods = ['getSelectedPresetName','getCurrentPresetName','getPresetName'];
    for(const name of methods){
      try {
        const value = pm?.[name]?.();
        if(typeof value === 'string' && value.trim()) return value.trim();
        if(value && typeof value === 'object'){
          const n = value.name || value.presetName || value.preset_name || value.id;
          if(n != null && String(n).trim()) return String(n).trim();
        }
      } catch(e) {}
    }
    const props = ['selectedPresetName','currentPresetName','presetName','preset_name','selectedPreset','currentPreset','preset'];
    for(const name of props){
      try {
        const value = pm?.[name];
        if(typeof value === 'string' && value.trim()) return value.trim();
        if(value && typeof value === 'object'){
          const n = value.name || value.presetName || value.preset_name || value.id;
          if(n != null && String(n).trim()) return String(n).trim();
        }
      } catch(e) {}
    }
    return '';
  }

  function getVisiblePresetSelectValue(){
    try {
      const selects = [...DOC.querySelectorAll('select[id*="preset" i],select[name*="preset" i]')]
        .filter(el => !el.disabled && el.isConnected);
      // 优先当前可见的预设选择框；面板关闭时再回退到有值的选择框。
      const visible = selects.filter(el => {
        try {
          const st = ROOT.getComputedStyle?.(el);
          return st?.display !== 'none' && st?.visibility !== 'hidden' && el.getClientRects().length > 0;
        } catch(e) { return false; }
      });
      const pool = visible.length ? visible : selects;
      for(const el of pool){
        const value = String(el.value ?? '').trim();
        const text = String(el.selectedOptions?.[0]?.textContent ?? '').trim();
        if(value || text) return (el.id || el.name || 'preset') + ':' + value + ':' + text;
      }
    } catch(e) {}
    return '';
  }

  function getPresetLifecycleSignature(){
    try {
      const ctx = ROOT.SillyTavern?.getContext?.();
      let pm = null;
      try { pm = typeof ctx?.getPresetManager === 'function' ? ctx.getPresetManager() : null; } catch(e) {}
      const managerName = readPresetManagerName(pm);
      const api = String(
        ctx?.mainApi ?? ctx?.main_api ?? ROOT.main_api ??
        DOC.querySelector('#main_api')?.value ?? DOC.querySelector('[name="main_api"]')?.value ?? ''
      ).trim();
      const known = [
        managerName,
        ctx?.chatCompletionSettings?.preset,
        ctx?.oaiSettings?.preset,
        ROOT.oai_settings?.preset_settings_openai,
        ROOT.textgenerationwebui_settings?.preset,
        ROOT.koboldai_settings?.preset,
        getVisiblePresetSelectValue()
      ].map(x => String(x ?? '').trim()).filter(Boolean);
      const preset = known[0] || '';
      return api || preset ? JSON.stringify({api,preset}) : '';
    } catch(e) { return ''; }
  }

  function cleanupForPresetBoundary(reason){
    if(ccCleaned || !presetLifecycleArmed) return;
    // 推迟到当前 PRESET_CHANGED 分发结束，避免阻断酒馆自身的其他监听器。
    ccSetTimeout(()=>{
      if(!ccCleaned && presetLifecycleArmed) clawedCleanup(reason || 'preset-changed');
    }, 0);
  }

  function bindPresetLifecycleEvents(){
    if(ccCleaned) return false;
    if(presetLifecycleBound) return true;
    try {
      const ctx = ROOT.SillyTavern?.getContext?.();
      const es = ctx?.eventSource || ROOT.eventSource;
      const et = ctx?.event_types || ROOT.event_types;
      if(!es?.on || !et) return false;
      const bindings = [
        [et.PRESET_CHANGED, 'preset-changed'],
        [et.MAIN_API_CHANGED, 'main-api-changed']
      ].filter(([event]) => !!event);
      if(!bindings.length) return false;
      bindings.forEach(([event, reason]) => {
        const handler = () => cleanupForPresetBoundary(reason);
        es.on(event, handler);
        addCleanupStop(()=>{
          try {
            if(typeof es.off === 'function') es.off(event, handler);
            else if(typeof es.removeListener === 'function') es.removeListener(event, handler);
          } catch(e) {}
        });
      });
      presetLifecycleBound = true;
      return true;
    } catch(e) { return false; }
  }

  // 旧实例已运行一段时间时会响应切换；刚由“新预设”创建的实例先保持未武装，
  // 避免它接到同一轮 PRESET_CHANGED 尾声后把自己误杀。
  bindPresetLifecycleEvents();
  [300, 900, 1800, 3200].forEach(ms=>ccSetTimeout(bindPresetLifecycleEvents, ms));
  ccSetTimeout(()=>{
    if(ccCleaned) return;
    presetLifecycleSignature = getPresetLifecycleSignature();
    presetLifecycleArmed = true;
  }, 1200);

  // 兼容旧版/魔改版酒馆没有 PRESET_CHANGED，或 Tavern Helper 没把 eventSource 暴露给 iframe。
  // 只有能稳定读取到预设身份时才启用比较，避免空值造成误清理。
  ccSetInterval(()=>{
    if(ccCleaned || !presetLifecycleArmed) return;
    const now = getPresetLifecycleSignature();
    if(!presetLifecycleSignature){
      if(now) presetLifecycleSignature = now;
      return;
    }
    if(now && now !== presetLifecycleSignature) cleanupForPresetBoundary('preset-signature-changed');
  }, 750);

  // Tavern Helper 官方推荐 pagehide；同时兼容原生事件、jQuery 合成事件和 iframe 被直接移除的情况。
  addCleanupListener(window, 'pagehide', clawedCleanup);
  addCleanupListener(window, 'beforeunload', clawedCleanup);
  addCleanupListener(window, 'unload', clawedCleanup);
  addCleanupListener(ROOT, 'pagehide', clawedCleanup);
  addCleanupListener(ROOT, 'unload', clawedCleanup);
  try {
    const jq = window.jQuery || window.$;
    if(typeof jq === 'function'){
      const jqWin = jq(window);
      const ns = '.clawedLifecycle';
      if(jqWin?.on){ jqWin.on('pagehide'+ns, clawedCleanup); addCleanupStop(()=>jqWin.off(ns)); }
    }
  } catch(e) {}
  try {
    const scriptFrame = window.frameElement;
    if(scriptFrame){
      const frameObserver = new MutationObserver(()=>{ if(!scriptFrame.isConnected) clawedCleanup('frame-detached'); });
      frameObserver.observe(DOC.documentElement,{childList:true,subtree:true});
      ccObservers.push(frameObserver);
      ccSetInterval(()=>{ if(!scriptFrame.isConnected) clawedCleanup('frame-detached-watchdog'); },1000);
    }
  } catch(e) {}

})();
